const e=[{id:"subject-pronouns",title:"Subject Pronouns",emoji:"👤📝",description:"I, you, he, she...",module:2,order:1,slides:[{type:"title",emoji:"👤📝",title:"SUBJECT PRONOUNS",subtitle:"Eu, você, ele, ela..."},{type:"situation",emoji:"🍔",cardClass:"cyan",text:'Primeiro dia como ajudante de cozinha num restaurante. O gerente fala rápido, apresenta todo mundo de uma vez: "She is the chef. He does the dishes. They are on break."<br><br>Se você não sabe quem é HE, SHE, THEY... você não sabe de quem estão falando. Pronomes são as primeiras palavras que você precisa pra entender QUEM faz O QUÊ.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"👋",english:"Welcome! I am the manager. You are on prep today.",portuguese:"Bem-vindo! Eu sou o gerente. Você tá na preparação hoje.",breakdown:"<strong>I AM</strong> = eu sou. <strong>YOU ARE</strong> = você está/é. O gerente se apresenta e já te coloca pra trabalhar."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"👩‍🍳",english:"She is the head chef. He is the dishwasher. They are fast!",portuguese:"Ela é a chef. Ele é o lavador de pratos. Eles são rápidos!",breakdown:"<strong>SHE</strong> = ela. <strong>HE</strong> = ele. <strong>THEY</strong> = eles/elas. Cada pessoa = um pronome."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"👥",english:"We start at 10. It is busy on weekends.",portuguese:"Começamos às 10. Fim de semana é corrido.",breakdown:"<strong>WE</strong> = nós (a equipe). <strong>IT IS</strong> = é/está. IT pra situações e coisas."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"✅",english:"Got it. I am ready! Where do I put my stuff?",portuguese:"Entendi. Tô pronto! Onde coloco minhas coisas?",breakdown:"<strong>I AM READY</strong> = estou pronto. Frase essencial no primeiro dia de qualquer trabalho."},{type:"rule",cardClass:"cyan",text:"Pronomes <strong>SUJEITO</strong> = quem FAZ a ação:",keyword:"I, YOU, HE, SHE, IT, WE, THEY",keywordAfter:"Eu, você, ele, ela, isso, nós, eles"},{type:"tip",cardClass:"gold",icon:"📋",title:"TABELA COMPLETA",text:"<strong>I</strong> = Eu<br><strong>YOU</strong> = Você/Vocês<br><strong>HE</strong> = Ele | <strong>SHE</strong> = Ela<br><strong>IT</strong> = Isso (coisas/animais)<br><strong>WE</strong> = Nós | <strong>THEY</strong> = Eles/Elas"},{type:"example",cardClass:"cyan",emoji:"👤",question:'<span class="hl-cyan">I</span> am happy.',questionTr:"Eu estou feliz.",answer:"(eu = sujeito)",answerTr:"I = eu"},{type:"example",cardClass:"cyan",emoji:"👨",question:'<span class="hl-cyan">He</span> is my friend.',questionTr:"Ele é meu amigo.",answer:"(ele = sujeito)",answerTr:"HE = ele"},{type:"example",cardClass:"cyan",emoji:"👥",question:'<span class="hl-cyan">They</span> are here.',questionTr:"Eles estão aqui.",answer:"(eles = sujeito)",answerTr:"THEY = eles/elas"},{type:"examples",cardClass:"cyan",title:"👤 PRONOMES - SINGULAR",items:[{emoji:"👤",en:'<span class="hl-cyan">I</span> am Brazilian.',pt:"Eu sou brasileiro."},{emoji:"👆",en:'<span class="hl-cyan">You</span> are nice.',pt:"Você é legal."},{emoji:"👨",en:'<span class="hl-cyan">He</span> is tall.',pt:"Ele é alto."},{emoji:"👩",en:'<span class="hl-cyan">She</span> is a doctor.',pt:"Ela é médica."}]},{type:"examples",cardClass:"purple",title:"👥 PRONOMES - PLURAL",items:[{emoji:"👥",en:'<span class="hl-purple">We</span> are friends.',pt:"Nós somos amigos."},{emoji:"👥",en:'<span class="hl-purple">They</span> are teachers.',pt:"Eles são professores."},{emoji:"👆",en:'<span class="hl-purple">You</span> are all welcome.',pt:"Vocês são todos bem-vindos."}]},{type:"tip",cardClass:"green",icon:"💡",title:"IT - PARA COISAS E ANIMAIS",text:"<strong>IT</strong> é usado para coisas e animais:<br><br><strong>It</strong> is new. (O carro) É novo.<br><strong>It</strong> is big. (O cachorro) É grande."},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:'<span class="hl-red">Her</span> is my sister.',leftNote:"HER não é sujeito",right:'<span class="hl-green">She</span> is my sister.',rightNote:"SHE é sujeito",explanation:"HER = dela (posse) | SHE = ela (sujeito)"},{type:"quiz",cardClass:"cyan",question:'🎯 "Ela é minha irmã":',options:["Her is my sister","She is my sister","Hers is my sister"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Nós somos amigos":',options:["Us are friends","Our are friends","We are friends"],correct:2},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"_____ is my friend. (ele)",correctWord:"He"},{type:"list",cardClass:"gold",title:"📝 RESUMO - PRONOMES SUJEITO",items:[{emoji:"👤",text:"<strong>I</strong> = Eu | <strong>YOU</strong> = Você"},{emoji:"👫",text:"<strong>HE</strong> = Ele | <strong>SHE</strong> = Ela"},{emoji:"📦",text:"<strong>IT</strong> = Isso (coisas/animais)"},{emoji:"👥",text:"<strong>WE</strong> = Nós | <strong>THEY</strong> = Eles"}]},{type:"end"}],vocabulary:[{emoji:"👤",pt:"Eu sou brasileiro",en:"I am Brazilian"},{emoji:"👆",pt:"Você é legal",en:"You are nice"},{emoji:"👩",pt:"Ela é médica",en:"She is a doctor"},{emoji:"📦",pt:"Isso é novo",en:"It is new"},{emoji:"👥",pt:"Nós somos amigos",en:"We are friends"},{emoji:"👥",pt:"Eles são professores",en:"They are teachers"},{emoji:"🐕",pt:"Ele é grande (cachorro)",en:"It is big"},{emoji:"👨‍👩‍👧",pt:"Nós somos família",en:"We are family"},{emoji:"🏠",pt:"Eles moram aqui",en:"They live here"}]},{id:"object-pronouns",title:"Object Pronouns",emoji:"👤➡️",description:"me, you, him, her...",module:2,order:2,slides:[{type:"title",emoji:"👤➡️",title:"OBJECT PRONOUNS",subtitle:"me, te, ele, ela... (objeto)"},{type:"situation",emoji:"📦",cardClass:"cyan",text:'Dia de mudança. Você, sua esposa e dois amigos carregando tudo pro apartamento novo. "Give ME this." "Call HIM." "Text HER." "Help US with this."<br><br>Em português, a gente fala "me dá", "liga pra ele" sem pensar. Em inglês, o pronome MUDA quando vem depois do verbo: HE vira HIM, SHE vira HER, WE vira US. Se usa errado, ninguém entende quem faz o quê.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"📦",english:"Give me that box. Careful — don't drop it!",portuguese:"Me dá essa caixa. Cuidado — não derruba!",breakdown:"<strong>GIVE ME</strong> = me dá. ME = eu (depois do verbo). <strong>IT</strong> = ela/a caixa (objeto)."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"📞",english:"Call him — he has the truck key. Tell him to hurry up.",portuguese:"Liga pra ele — ele tem a chave do caminhão. Fala pra ele se apressar.",breakdown:"<strong>CALL HIM</strong> = liga pra ele. HE → HIM depois do verbo. <strong>TELL HIM</strong> = fala pra ele."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"💬",english:"My wife? Text her. Tell her we need more tape.",portuguese:"Minha esposa? Manda mensagem pra ela. Fala que precisa de mais fita.",breakdown:"<strong>TEXT HER</strong> = manda mensagem pra ela. SHE → HER depois do verbo."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"🙏",english:"Thanks for helping us! Let me buy you lunch.",portuguese:"Obrigado por ajudar a gente! Deixa eu pagar o almoço.",breakdown:"<strong>HELPING US</strong> = ajudando a gente. WE → US depois do verbo. <strong>BUY YOU</strong> = pagar pra você."},{type:"rule",cardClass:"orange",text:"Pronomes <strong>OBJETO</strong> = quem RECEBE a ação:",keyword:"ME, YOU, HIM, HER, IT, US, THEM",keywordAfter:"Me, te, ele, ela, isso, nos, eles"},{type:"tip",cardClass:"gold",icon:"📋",title:"TABELA COMPLETA",text:"<strong>ME</strong> = Me/Mim<br><strong>YOU</strong> = Te/Você<br><strong>HIM</strong> = Ele/O | <strong>HER</strong> = Ela/A<br><strong>IT</strong> = Isso<br><strong>US</strong> = Nos/Nós | <strong>THEM</strong> = Eles/Os"},{type:"example",cardClass:"orange",emoji:"📞",question:'Call <span class="hl-orange">me</span>.',questionTr:"Me liga.",answer:"(me = objeto)",answerTr:"Quem recebe"},{type:"example",cardClass:"orange",emoji:"👀",question:'I saw <span class="hl-orange">him</span>.',questionTr:"Eu vi ele.",answer:"(him = objeto)",answerTr:"Quem recebe"},{type:"example",cardClass:"orange",emoji:"💝",question:'I love <span class="hl-orange">her</span>.',questionTr:"Eu amo ela.",answer:"(her = objeto)",answerTr:"Quem recebe"},{type:"examples",cardClass:"orange",title:"👤 OBJETOS - SINGULAR",items:[{emoji:"🆘",en:'Help <span class="hl-orange">me</span>.',pt:"Me ajuda."},{emoji:"🎁",en:'This is for <span class="hl-orange">you</span>.',pt:"Isso é pra você."},{emoji:"📞",en:'Call <span class="hl-orange">him</span>.',pt:"Liga pra ele."},{emoji:"✉️",en:'Send it to <span class="hl-orange">her</span>.',pt:"Manda pra ela."}]},{type:"examples",cardClass:"purple",title:"👥 OBJETOS - PLURAL",items:[{emoji:"👋",en:'Wait for <span class="hl-purple">us</span>.',pt:"Espera por nós."},{emoji:"🗣️",en:'Talk to <span class="hl-purple">them</span>.',pt:"Fala com eles."},{emoji:"🎁",en:"It's for <span class='hl-purple'>us</span>.",pt:"É pra nós."}]},{type:"comparison",cardClass:"cyan",title:"👤 SUJEITO vs OBJETO 👤➡️",leftClass:"left-side",rightClass:"right-side",leftIcon:"👤",rightIcon:"➡️",leftLabel:"SUJEITO (faz)",rightLabel:"OBJETO (recebe)",left:'<span class="hl-cyan">He</span> called me.',leftNote:"ELE faz a ação",right:'I called <span class="hl-orange">him</span>.',rightNote:"ELE recebe a ação",explanation:"HE = sujeito | HIM = objeto"},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:'Help <span class="hl-red">I</span>.',leftNote:"I é sujeito",right:'Help <span class="hl-green">me</span>.',rightNote:"ME é objeto",explanation:"Depois de verbos, use pronome OBJETO!"},{type:"quiz",cardClass:"cyan",question:'🎯 "Me ajuda":',options:["Help I","Help me","Help my"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Eu vi eles":',options:["I saw they","I saw them","I saw their"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"Call _____ later. (ele)",correctWord:"him"},{type:"list",cardClass:"gold",title:"📝 RESUMO - PRONOMES OBJETO",items:[{emoji:"👤",text:"<strong>ME</strong> = me | <strong>YOU</strong> = te"},{emoji:"👫",text:"<strong>HIM</strong> = ele | <strong>HER</strong> = ela"},{emoji:"📦",text:"<strong>IT</strong> = isso"},{emoji:"👥",text:"<strong>US</strong> = nós | <strong>THEM</strong> = eles"}]},{type:"end"}],vocabulary:[{emoji:"📞",pt:"Me liga",en:"Call me"},{emoji:"👀",pt:"Eu vi ele",en:"I saw him"},{emoji:"💝",pt:"Eu amo ela",en:"I love her"},{emoji:"🗣️",pt:"Fala com eles",en:"Talk to them"},{emoji:"🆘",pt:"Me ajuda",en:"Help me"},{emoji:"📱",pt:"Me manda mensagem",en:"Text me"},{emoji:"👋",pt:"Espera por nós",en:"Wait for us"},{emoji:"🎁",pt:"Isso é pra você",en:"This is for you"},{emoji:"✉️",pt:"Manda pra ela",en:"Send it to her"},{emoji:"🚗",pt:"Me leva",en:"Take me"}]},{id:"possessive-adjectives",title:"Possessive Adjectives",emoji:"👤📦",description:"my, your, his, her...",module:2,order:3,slides:[{type:"title",emoji:"👤📦",title:"POSSESSIVE ADJECTIVES",subtitle:"meu, seu, dele, dela..."},{type:"situation",emoji:"🏫",cardClass:"cyan",text:'Fim do dia na escola. Você busca seu filho e encontra uma mãe americana. "Is that YOUR son? MY daughter is in HIS class! THEIR teacher said OUR kids are friends."<br><br>Na escola, na igreja, no trabalho — todo mundo fala de pertences e família o tempo todo. MY, YOUR, HIS, HER, OUR, THEIR. Se você troca HIS por HER, de repente está falando da pessoa errada.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"👋",english:"Is that your son? My daughter is in his class!",portuguese:"Esse é seu filho? Minha filha tá na turma dele!",breakdown:"<strong>YOUR</strong> = seu. <strong>MY</strong> = meu/minha. <strong>HIS</strong> = dele. Cada pessoa tem seu possessivo."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"😊",english:"Yes! Her name is Emma, right? Our kids are friends.",portuguese:"Sim! O nome dela é Emma, né? Nossos filhos são amigos.",breakdown:"<strong>HER</strong> name = o nome DELA. <strong>OUR</strong> kids = NOSSOS filhos."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"👩‍🏫",english:"Their teacher is great. She knows my son is learning English.",portuguese:"A professora deles é ótima. Ela sabe que meu filho tá aprendendo inglês.",breakdown:"<strong>THEIR</strong> teacher = a professora DELES. <strong>MY</strong> son = MEU filho."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"🎒",english:"Is this his backpack? No, it's hers. His is the blue one.",portuguese:"Essa mochila é dele? Não, é dela. A dele é a azul.",breakdown:"<strong>HIS</strong> backpack = mochila DELE. <strong>HERS</strong> = dela (sem noun depois)."},{type:"rule",cardClass:"green",text:"Adjetivos <strong>POSSESSIVOS</strong> = mostram de QUEM é:",keyword:"MY, YOUR, HIS, HER, ITS, OUR, THEIR",keywordAfter:"Meu, seu, dele, dela, seu, nosso, deles"},{type:"tip",cardClass:"gold",icon:"📋",title:"TABELA COMPLETA",text:"<strong>MY</strong> = Meu/Minha<br><strong>YOUR</strong> = Seu/Sua<br><strong>HIS</strong> = Dele | <strong>HER</strong> = Dela<br><strong>ITS</strong> = Seu (coisas/animais)<br><strong>OUR</strong> = Nosso | <strong>THEIR</strong> = Deles"},{type:"example",cardClass:"green",emoji:"📱",question:'This is <span class="hl-green">my</span> phone.',questionTr:"Este é meu celular.",answer:"(meu)",answerTr:"Posse"},{type:"example",cardClass:"green",emoji:"🚗",question:'<span class="hl-green">His</span> car is new.',questionTr:"O carro dele é novo.",answer:"(dele)",answerTr:"Posse"},{type:"example",cardClass:"green",emoji:"🏠",question:'<span class="hl-green">Her</span> house is big.',questionTr:"A casa dela é grande.",answer:"(dela)",answerTr:"Posse"},{type:"examples",cardClass:"green",title:"👤 POSSESSIVOS - SINGULAR",items:[{emoji:"📱",en:'<span class="hl-green">My</span> phone',pt:"Meu celular"},{emoji:"🏠",en:'<span class="hl-green">Your</span> house',pt:"Sua casa"},{emoji:"🚗",en:'<span class="hl-green">His</span> car',pt:"O carro dele"},{emoji:"👜",en:'<span class="hl-green">Her</span> bag',pt:"A bolsa dela"}]},{type:"examples",cardClass:"purple",title:"👥 POSSESSIVOS - PLURAL",items:[{emoji:"🏠",en:'<span class="hl-purple">Our</span> house',pt:"Nossa casa"},{emoji:"👨‍👩‍👧",en:'<span class="hl-purple">Their</span> family',pt:"A família deles"},{emoji:"📚",en:'<span class="hl-purple">Our</span> books',pt:"Nossos livros"}]},{type:"tip",cardClass:"green",icon:"💡",title:"HIS vs HER",text:"<strong>HIS</strong> = dele (homem é dono)<br><strong>HER</strong> = dela (mulher é dona)<br><br>O gênero segue o DONO, não a coisa!"},{type:"comparison",cardClass:"cyan",title:"👨 HIS vs HER 👩",leftClass:"left-side",rightClass:"right-side",leftIcon:"👨",rightIcon:"👩",leftLabel:"HIS (dele)",rightLabel:"HER (dela)",left:'<span class="hl-cyan">His</span> car = carro DELE',leftNote:"Homem é dono",right:'<span class="hl-purple">Her</span> car = carro DELA',rightNote:"Mulher é dona",explanation:"O gênero segue o DONO!"},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:'<span class="hl-red">He</span> car is new.',leftNote:"HE é sujeito",right:'<span class="hl-green">His</span> car is new.',rightNote:"HIS é possessivo",explanation:"HE = ele (sujeito) | HIS = dele (posse)"},{type:"quiz",cardClass:"cyan",question:'🎯 "O carro dele":',options:["He car","Him car","His car"],correct:2},{type:"quiz",cardClass:"cyan",question:'🎯 "A casa dela":',options:["She house","Her house","Hers house"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"This is _____ phone. (meu)",correctWord:"my"},{type:"list",cardClass:"gold",title:"📝 RESUMO - POSSESSIVOS",items:[{emoji:"👤",text:"<strong>MY</strong> = meu | <strong>YOUR</strong> = seu"},{emoji:"👫",text:"<strong>HIS</strong> = dele | <strong>HER</strong> = dela"},{emoji:"📦",text:"<strong>ITS</strong> = seu (coisas)"},{emoji:"👥",text:"<strong>OUR</strong> = nosso | <strong>THEIR</strong> = deles"}]},{type:"end"}],vocabulary:[{emoji:"📱",pt:"Meu celular",en:"My phone"},{emoji:"🏠",pt:"Sua casa",en:"Your house"},{emoji:"🚗",pt:"O carro dele",en:"His car"},{emoji:"👜",pt:"A bolsa dela",en:"Her bag"},{emoji:"🐕",pt:"Nosso cachorro",en:"Our dog"},{emoji:"👨‍👩‍👧",pt:"A família deles",en:"Their family"},{emoji:"📚",pt:"Meus livros",en:"My books"},{emoji:"💼",pt:"Seu trabalho",en:"Your job"},{emoji:"🎂",pt:"Meu aniversário",en:"My birthday"},{emoji:"👦",pt:"O filho dela",en:"Her son"}]},{id:"a-an",title:"A / AN",emoji:"1️⃣📝",description:"Artigos indefinidos",module:2,order:4,slides:[{type:"title",emoji:"1️⃣📝",title:"A / AN",subtitle:"Um / Uma (artigos indefinidos)"},{type:"situation",emoji:"🛒",cardClass:"cyan",text:'Hora do almoço na obra. Você vai no food truck com o colega. "Can I get A burger? And AN iced tea." O cara atrás de você pede: "AN orange juice and A hot dog."<br><br>A ou AN? A regra é simples: depende do SOM da próxima palavra. Som de vogal (A, E, I, O, U) → AN. Se não → A. Ninguém vai te corrigir se errar, mas soa estranho — tipo falar "um a maçã" em português.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🍔",english:"Hi! Can I get a burger and an iced tea?",portuguese:"Oi! Quero um hambúrguer e um chá gelado.",breakdown:"<strong>A</strong> burger (som de consoante B). <strong>AN</strong> iced tea (som de vogal I). O SOM decide!"},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"🍖",english:"Sure! Do you want an extra patty? It's a dollar more.",portuguese:"Claro! Quer um hambúrguer extra? É um dólar a mais.",breakdown:"<strong>AN</strong> extra (som de vogal E). <strong>A</strong> dollar (som de consoante D)."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"🌭",english:"No thanks. For him — a hot dog and an orange juice.",portuguese:"Não, obrigado. Pra ele — um cachorro-quente e um suco de laranja.",breakdown:"<strong>A</strong> hot dog (H = consoante). <strong>AN</strong> orange (O = vogal). Sempre o som da PRIMEIRA LETRA."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"💰",english:"That's a total of twelve dollars. Have a good one!",portuguese:"Dá doze dólares. Tenha um bom dia!",breakdown:"<strong>A TOTAL</strong> = um total. <strong>HAVE A GOOD ONE</strong> = tenha um bom dia. Expressão super americana!"},{type:"rule",cardClass:"cyan",text:"<strong>A</strong> = antes de SOM de CONSOANTE<br><strong>AN</strong> = antes de SOM de VOGAL:",keyword:"A car, AN apple",keywordAfter:"O som é que importa, não a letra!"},{type:"tip",cardClass:"gold",icon:"⭐",title:"REGRA SIMPLES",text:"Vogais: <strong>A, E, I, O, U</strong><br><br>Antes de VOGAL → <strong>AN</strong><br>Antes de CONSOANTE → <strong>A</strong>"},{type:"example",cardClass:"cyan",emoji:"🚗",question:'I have <span class="hl-cyan">a</span> car.',questionTr:"Eu tenho um carro.",answer:"(C = consoante)",answerTr:"A + car"},{type:"example",cardClass:"orange",emoji:"🍎",question:'I want <span class="hl-orange">an</span> apple.',questionTr:"Eu quero uma maçã.",answer:"(A = vogal)",answerTr:"AN + apple"},{type:"example",cardClass:"orange",emoji:"🥚",question:'I ate <span class="hl-orange">an</span> egg.',questionTr:"Eu comi um ovo.",answer:"(E = vogal)",answerTr:"AN + egg"},{type:"examples",cardClass:"cyan",title:"🔤 A + CONSOANTE",items:[{emoji:"📖",en:'<span class="hl-cyan">A</span> book',pt:"Um livro"},{emoji:"🏠",en:'<span class="hl-cyan">A</span> house',pt:"Uma casa"},{emoji:"🐕",en:'<span class="hl-cyan">A</span> dog',pt:"Um cachorro"},{emoji:"👩‍⚕️",en:'<span class="hl-cyan">A</span> doctor',pt:"Um médico"}]},{type:"examples",cardClass:"orange",title:"🔠 AN + VOGAL",items:[{emoji:"🍊",en:'<span class="hl-orange">An</span> orange',pt:"Uma laranja"},{emoji:"☂️",en:'<span class="hl-orange">An</span> umbrella',pt:"Um guarda-chuva"},{emoji:"💡",en:'<span class="hl-orange">An</span> idea',pt:"Uma ideia"},{emoji:"🏢",en:'<span class="hl-orange">An</span> office',pt:"Um escritório"}]},{type:"tip",cardClass:"purple",icon:"⚠️",title:"EXCEÇÕES IMPORTANTES",text:"O que importa é o <strong>SOM</strong>, não a letra!<br><br>❌ a hour → ✅ <strong>an</strong> hour (H mudo!)<br>❌ an university → ✅ <strong>a</strong> university (som de Y!)"},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:'<span class="hl-red">a</span> hour',leftNote:"H é mudo!",right:'<span class="hl-green">an</span> hour',rightNote:"Som de vogal",explanation:'HOUR tem H mudo → som de "our"!'},{type:"quiz",cardClass:"cyan",question:'🎯 "Uma hora":',options:["a hour","an hour","one hour"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Uma universidade":',options:["an university","a university","the university"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"I want _____ apple.",correctWord:"an"},{type:"list",cardClass:"gold",title:"📝 RESUMO - A / AN",items:[{emoji:"🔤",text:"<strong>A</strong> = antes de SOM de consoante"},{emoji:"🔠",text:"<strong>AN</strong> = antes de SOM de vogal"},{emoji:"⚠️",text:"AN hour (H mudo)"},{emoji:"⚠️",text:"A university (som de Y)"}]},{type:"end"}],vocabulary:[{emoji:"🚗",pt:"Um carro",en:"A car"},{emoji:"🍎",pt:"Uma maçã",en:"An apple"},{emoji:"📖",pt:"Um livro",en:"A book"},{emoji:"🥚",pt:"Um ovo",en:"An egg"},{emoji:"🏠",pt:"Uma casa",en:"A house"},{emoji:"☂️",pt:"Um guarda-chuva",en:"An umbrella"},{emoji:"⏰",pt:"Uma hora",en:"An hour"},{emoji:"🎓",pt:"Uma universidade",en:"A university"},{emoji:"🍊",pt:"Uma laranja",en:"An orange"},{emoji:"🐕",pt:"Um cachorro",en:"A dog"}]},{id:"the",title:"THE",emoji:"☝️📝",description:"Artigo definido",module:2,order:5,slides:[{type:"title",emoji:"☝️📝",title:"THE",subtitle:"O / A / Os / As (artigo definido)"},{type:"situation",emoji:"📦",cardClass:"cyan",text:`Primeiro dia num warehouse. O supervisor te mostra tudo: "THE bathroom is there. THE break room is upstairs. Don't touch THE forklift."<br><br>THE é "o/a" — aponta pra algo ESPECÍFICO que todo mundo sabe qual é. "A bathroom" = qualquer banheiro. "THE bathroom" = AQUELE banheiro ali. Em português a gente nem pensa nisso. Em inglês, se esquece THE, a frase soa incompleta.`},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🚻",english:"OK, come with me. The bathroom is over there. The break room is upstairs.",portuguese:"Vem comigo. O banheiro é ali. A sala de descanso é lá em cima.",breakdown:"<strong>THE</strong> bathroom = O banheiro específico DESSE lugar. Todo mundo sabe qual é."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"🏗️",english:"See the forklift? Don't touch the forklift without training.",portuguese:"Tá vendo a empilhadeira? Não mexe nela sem treinamento.",breakdown:"<strong>THE</strong> forklift = AQUELA empilhadeira ali. Só tem uma. Ambos estão vendo."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"📦",english:"The boxes go on the shelves. Stack them by the wall.",portuguese:"As caixas vão nas prateleiras. Empilha perto da parede.",breakdown:"<strong>THE</strong> boxes = AS caixas (que estão aqui). <strong>THE</strong> shelves = AS prateleiras (que você tá vendo)."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"👔",english:"The manager comes at 3. If you need help, ask the guy in the red shirt.",portuguese:"O gerente chega às 3. Se precisar de ajuda, pergunta pro cara de camisa vermelha.",breakdown:"<strong>THE</strong> manager = O gerente (todo mundo sabe quem é). <strong>THE</strong> guy in the red shirt = aquele cara específico."},{type:"rule",cardClass:"green",text:"<strong>THE</strong> = algo ESPECÍFICO que ambos conhecem:",keyword:"THE",keywordAfter:"O / A / Os / As (singular e plural!)"},{type:"tip",cardClass:"gold",icon:"⭐",title:"THE - UM PARA TODOS",text:"THE serve para TUDO:<br><br><strong>the</strong> car = o carro<br><strong>the</strong> house = a casa<br><strong>the</strong> books = os livros<br><strong>the</strong> girls = as meninas"},{type:"example",cardClass:"green",emoji:"🚗",question:'<span class="hl-green">The</span> car is red.',questionTr:"O carro é vermelho.",answer:"(específico)",answerTr:"Qual carro? ESSE carro."},{type:"example",cardClass:"green",emoji:"🚪",question:'Close <span class="hl-green">the</span> door.',questionTr:"Fecha a porta.",answer:"(específico)",answerTr:"Qual porta? ESSA porta."},{type:"example",cardClass:"green",emoji:"📚",question:'<span class="hl-green">The</span> books are here.',questionTr:"Os livros estão aqui.",answer:"(específico)",answerTr:"Plural também!"},{type:"examples",cardClass:"green",title:"☝️ COISAS ÚNICAS (sempre THE)",items:[{emoji:"☀️",en:'<span class="hl-green">The</span> sun',pt:"O sol (só tem um!)"},{emoji:"🌙",en:'<span class="hl-green">The</span> moon',pt:"A lua"},{emoji:"🌍",en:'<span class="hl-green">The</span> world',pt:"O mundo"},{emoji:"🏛️",en:'<span class="hl-green">The</span> president',pt:"O presidente"}]},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA DO THE",text:'Dois sons diferentes!<br><br>Antes de CONSOANTE: "dã"<br>→ <strong>the</strong> car (dã car)<br><br>Antes de VOGAL: "di"<br>→ <strong>the</strong> apple (di apple)'},{type:"comparison",cardClass:"cyan",title:"1️⃣ A/AN vs THE ☝️",leftClass:"left-side",rightClass:"right-side",leftIcon:"1️⃣",rightIcon:"☝️",leftLabel:"A/AN (qualquer um)",rightLabel:"THE (específico)",left:'I want <span class="hl-cyan">a</span> car.',leftNote:"Qualquer carro",right:'I want <span class="hl-green">the</span> car.',rightNote:"ESSE carro específico",explanation:"A/AN = um qualquer | THE = esse específico"},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:'I like <span class="hl-red">the</span> pizza.',leftNote:"Pizza em geral",right:"I like pizza.",rightNote:"Sem artigo",explanation:"Coisas em GERAL = sem artigo!"},{type:"quiz",cardClass:"cyan",question:'🎯 "O sol":',options:["A sun","Sun","The sun"],correct:2},{type:"quiz",cardClass:"cyan",question:'🎯 "Fecha a porta":',options:["Close door","Close a door","Close the door"],correct:2},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"_____ books are on the table.",correctWord:"The"},{type:"list",cardClass:"gold",title:"📝 RESUMO - THE",items:[{emoji:"☝️",text:"<strong>THE</strong> = específico/conhecido"},{emoji:"🔄",text:"Singular e plural: the car, the cars"},{emoji:"☀️",text:"Coisas únicas: the sun, the moon"},{emoji:"🗣️",text:'Som: "dã" ou "di" (antes de vogal)'}]},{type:"end"}],vocabulary:[{emoji:"🚗",pt:"O carro",en:"The car"},{emoji:"🌙",pt:"A lua",en:"The moon"},{emoji:"☀️",pt:"O sol",en:"The sun"},{emoji:"🏠",pt:"A casa",en:"The house"},{emoji:"📚",pt:"Os livros",en:"The books"},{emoji:"🚪",pt:"A porta",en:"The door"},{emoji:"🌍",pt:"O mundo",en:"The world"},{emoji:"🏥",pt:"O hospital",en:"The hospital"},{emoji:"🏫",pt:"A escola",en:"The school"},{emoji:"👔",pt:"O chefe",en:"The boss"}]},{id:"this",title:"THIS",emoji:"👆📍",description:"Isto/Este (perto)",module:2,order:6,slides:[{type:"title",emoji:"👆📍",title:"THIS",subtitle:"Isto/Este/Esta (perto de mim)"},{type:"situation",emoji:"🛒",cardClass:"cyan",text:'Você tá na Home Depot segurando uma lata de tinta. Precisa perguntar: "Is THIS the right one?" Segura um pincel: "How much is THIS?"<br><br>THIS é pra coisas PERTO de você — na sua mão, do seu lado. Sempre que você pode TOCAR ou SEGURAR, é THIS. Você vai usar THIS o dia inteiro: this is good, this is mine, what is this?'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🎨",english:"Excuse me, is this the right paint for bathrooms?",portuguese:"Com licença, essa é a tinta certa pra banheiro?",breakdown:"<strong>IS THIS</strong> = isso é? THIS = o que está NA SUA MÃO ou PERTO de você."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"✅",english:"Yes, this one is waterproof. This is what you need.",portuguese:"Sim, essa é à prova d'água. Essa é o que você precisa.",breakdown:"<strong>THIS ONE</strong> = essa aqui (específica). <strong>THIS IS</strong> = isso é."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"💰",english:"How much is this? And this brush — is this good quality?",portuguese:"Quanto custa isso? E esse pincel — é boa qualidade?",breakdown:"<strong>HOW MUCH IS THIS</strong> = quanto custa isso (que estou segurando)? Frase essencial em qualquer loja."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"🏷️",english:"This is on sale today! Twenty percent off.",portuguese:"Isso tá em promoção hoje! Vinte por cento de desconto.",breakdown:"<strong>THIS IS ON SALE</strong> = isso tá em promoção. ON SALE = em promoção. Palavra mágica nas compras!"},{type:"rule",cardClass:"cyan",text:"Para apontar algo <strong>PERTO</strong> de você (singular):",keyword:"THIS",keywordAfter:"Este/Esta/Isto (perto, singular)"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>THIS</strong> soa como "DIS"<br><br>O TH é suave, com a língua entre os dentes.'},{type:"example",cardClass:"cyan",emoji:"📱",question:'<span class="hl-cyan">This</span> is my phone.',questionTr:"Este é meu celular.",answer:"(perto)",answerTr:"Na minha mão"},{type:"example",cardClass:"cyan",emoji:"🏠",question:'<span class="hl-cyan">This</span> is my house.',questionTr:"Esta é minha casa.",answer:"(perto)",answerTr:"Estamos aqui"},{type:"example",cardClass:"cyan",emoji:"👨",question:'<span class="hl-cyan">This</span> is my brother.',questionTr:"Este é meu irmão.",answer:"(perto)",answerTr:"Ao meu lado"},{type:"examples",cardClass:"cyan",title:"👆 THIS - USOS COMUNS",items:[{emoji:"🍕",en:'<span class="hl-cyan">This</span> is delicious!',pt:"Isso é delicioso!"},{emoji:"📖",en:'<span class="hl-cyan">This</span> is important.',pt:"Isto é importante."},{emoji:"🎁",en:'<span class="hl-cyan">This</span> is for you.',pt:"Isto é pra você."},{emoji:"💡",en:'<span class="hl-cyan">This</span> is a good idea.',pt:"Esta é uma boa ideia."}]},{type:"tip",cardClass:"green",icon:"💡",title:"PERGUNTA ESSENCIAL",text:'<strong>"What is this?"</strong><br>O que é isso?<br><br>Use quando segura algo ou aponta para algo perto.'},{type:"comparison",cardClass:"cyan",title:"👆 THIS vs THAT 👉",leftClass:"left-side",rightClass:"right-side",leftIcon:"👆",rightIcon:"👉",leftLabel:"THIS (perto)",rightLabel:"THAT (longe)",left:'<span class="hl-cyan">This</span> is my car.',leftNote:"Carro aqui do lado",right:'<span class="hl-orange">That</span> is my car.',rightNote:"Carro lá longe",explanation:"<strong>PERTO</strong> = THIS | <strong>LONGE</strong> = THAT"},{type:"examples",cardClass:"purple",title:"📞 NO TELEFONE",items:[{emoji:"📞",en:'<span class="hl-cyan">This</span> is Maria speaking.',pt:"Aqui é a Maria falando."},{emoji:"📞",en:'Who is <span class="hl-cyan">this</span>?',pt:"Quem é?"},{emoji:"📞",en:'Is <span class="hl-cyan">this</span> John?',pt:"É o John?"}]},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"This are my books.",leftNote:"THIS é singular",right:"These are my books.",rightNote:"THESE para plural",explanation:"THIS = singular | THESE = plural"},{type:"quiz",cardClass:"cyan",question:"🎯 Para algo PERTO e SINGULAR:",options:["That","This","These"],correct:1},{type:"quiz",cardClass:"cyan",question:"🎯 Apresentando alguém ao seu lado:",options:["That is my friend","This is my friend","These is my friend"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete (mostrando seu celular):",sentence:"_____ is my phone.",correctWord:"This"},{type:"list",cardClass:"gold",title:"📝 RESUMO - THIS",items:[{emoji:"👆",text:"<strong>THIS</strong> = isto/este/esta"},{emoji:"📍",text:"Usado para coisas PERTO"},{emoji:"1️⃣",text:"Singular (uma coisa)"},{emoji:"🔢",text:"Plural: THESE"}]},{type:"end"}],vocabulary:[{emoji:"📱",pt:"Este é meu celular",en:"This is my phone"},{emoji:"🏠",pt:"Esta é minha casa",en:"This is my house"},{emoji:"👨",pt:"Este é meu irmão",en:"This is my brother"},{emoji:"🍕",pt:"Isso é delicioso",en:"This is delicious"},{emoji:"✅",pt:"Isto está certo",en:"This is correct"},{emoji:"🆕",pt:"Isto é novo",en:"This is new"},{emoji:"🎁",pt:"Isto é pra você",en:"This is for you"},{emoji:"💡",pt:"Isto é uma boa ideia",en:"This is a good idea"}]},{id:"that",title:"THAT",emoji:"👉📍",description:"Aquilo/Aquele (longe)",module:2,order:7,slides:[{type:"title",emoji:"👉📍",title:"THAT",subtitle:"Aquilo/Aquele/Aquela (longe de mim)"},{type:"situation",emoji:"🏗️",cardClass:"cyan",text:'Você tá na obra e o contractor aponta pra uma parede do outro lado: "See THAT wall? THAT crack needs to be fixed." Ele aponta pro caminhão lá fora: "Is THAT your truck?"<br><br>THAT é pra coisas LONGE de você — do outro lado do cômodo, na rua, qualquer coisa que você não consegue tocar. THIS = perto (na mão). THAT = longe (lá). Simples assim.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🧱",english:"See that wall? That crack needs to be fixed.",portuguese:"Tá vendo aquela parede? Aquela rachadura precisa ser consertada.",breakdown:"<strong>THAT</strong> wall = AQUELA parede (longe de você). Você APONTA, não toca."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"⚡",english:"What is that? That's the new generator. Don't touch that.",portuguese:"O que é aquilo? É o gerador novo. Não toca naquilo.",breakdown:"<strong>WHAT IS THAT</strong> = o que é aquilo? <strong>THAT'S</strong> = contração de THAT IS."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"🚛",english:"Is that your truck over there? Move that, please.",portuguese:"Aquele é seu caminhão ali? Move aquilo, por favor.",breakdown:"<strong>IS THAT</strong> = aquele é? OVER THERE = ali longe. THAT pra coisas que você VÊ mas não TOCA."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"👍",english:"That was fast! Good job. That's exactly what I wanted.",portuguese:"Foi rápido! Bom trabalho. É exatamente o que eu queria.",breakdown:"<strong>THAT WAS</strong> = aquilo foi (passado). <strong>THAT'S</strong> = isso é. THAT também funciona pra comentar sobre algo."},{type:"rule",cardClass:"orange",text:"Para apontar algo <strong>LONGE</strong> de você (singular):",keyword:"THAT",keywordAfter:"Aquele/Aquela/Aquilo (longe, singular)"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:`<strong>THAT</strong> soa como "DÉT"<br><br>Contração: <strong>That's</strong> = "DÉTS"`},{type:"example",cardClass:"orange",emoji:"🏢",question:'<span class="hl-orange">That</span> is my office.',questionTr:"Aquele é meu escritório.",answer:"(longe)",answerTr:"Lá no prédio"},{type:"example",cardClass:"orange",emoji:"🚗",question:'<span class="hl-orange">That</span> is his car.',questionTr:"Aquele é o carro dele.",answer:"(longe)",answerTr:"Lá na rua"},{type:"example",cardClass:"orange",emoji:"👤",question:'Who is <span class="hl-orange">that</span>?',questionTr:"Quem é aquele?",answer:"(longe)",answerTr:"Pessoa distante"},{type:"examples",cardClass:"orange",title:"👉 THAT - USOS COMUNS",items:[{emoji:"🏠",en:'<span class="hl-orange">That</span> is her house.',pt:"Aquela é a casa dela."},{emoji:"❓",en:'What is <span class="hl-orange">that</span>?',pt:"O que é aquilo?"},{emoji:"✅",en:'<span class="hl-orange">That</span> is correct.',pt:"Aquilo está certo."},{emoji:"😊",en:'<span class="hl-orange">That</span> is amazing!',pt:"Aquilo é incrível!"}]},{type:"tip",cardClass:"green",icon:"💡",title:"EXPRESSÕES COM THAT'S",text:"Muito usadas no dia a dia:<br><br><strong>That's cool!</strong> = Que legal!<br><strong>That's right!</strong> = Isso mesmo!<br><strong>That's it!</strong> = É isso!"},{type:"comparison",cardClass:"cyan",title:"👆 THIS vs THAT 👉",leftClass:"left-side",rightClass:"right-side",leftIcon:"👆",rightIcon:"👉",leftLabel:"THIS (perto)",rightLabel:"THAT (longe)",left:'<span class="hl-cyan">This</span> book here.',leftNote:"Na minha mão",right:'<span class="hl-orange">That</span> book there.',rightNote:"Na prateleira",explanation:"Posso tocar? = <strong>THIS</strong> | Preciso andar? = <strong>THAT</strong>"},{type:"examples",cardClass:"gold",title:"⭐ THAT COMO RESPOSTA",items:[{emoji:"👍",en:"That's right!",pt:"Isso mesmo!"},{emoji:"😊",en:"That's great!",pt:"Que ótimo!"},{emoji:"😔",en:"That's too bad.",pt:"Que pena."},{emoji:"🎯",en:"That's the point!",pt:"Esse é o ponto!"}]},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"That are my cars.",leftNote:"THAT é singular",right:"Those are my cars.",rightNote:"THOSE para plural",explanation:"THAT = singular | THOSE = plural"},{type:"quiz",cardClass:"cyan",question:"🎯 Para algo LONGE e SINGULAR:",options:["This","That","Those"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Que legal!" em inglês:',options:["This's cool!","That's cool!","Those's cool!"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete (apontando para algo longe):",sentence:"_____ is my car over there.",correctWord:"That"},{type:"list",cardClass:"gold",title:"📝 RESUMO - THAT",items:[{emoji:"👉",text:"<strong>THAT</strong> = aquilo/aquele/aquela"},{emoji:"📍",text:"Usado para coisas LONGE"},{emoji:"1️⃣",text:"Singular (uma coisa)"},{emoji:"⭐",text:"Expressões: That's cool/right/great!"}]},{type:"end"}],vocabulary:[{emoji:"🏢",pt:"Aquele é meu escritório",en:"That is my office"},{emoji:"🚗",pt:"Aquele é o carro dele",en:"That is his car"},{emoji:"🏠",pt:"Aquela é a casa dela",en:"That is her house"},{emoji:"👤",pt:"Quem é aquele?",en:"Who is that?"},{emoji:"✅",pt:"Aquilo está certo",en:"That is correct"},{emoji:"😊",pt:"Que legal!",en:"That's cool!"},{emoji:"👍",pt:"Isso mesmo!",en:"That's right!"},{emoji:"🎯",pt:"É isso!",en:"That's it!"},{emoji:"💡",pt:"Boa ideia!",en:"That's a good idea!"}]},{id:"these-those",title:"THESE / THOSE",emoji:"👆👉",description:"Plural (perto/longe)",module:2,order:8,slides:[{type:"title",emoji:"👆👉",title:"THESE / THOSE",subtitle:"Plurais de THIS e THAT"},{type:"situation",emoji:"🛒",cardClass:"cyan",text:'No supermercado com a esposa. Você segura bananas: "THESE look good." Ela aponta pras maçãs lá no fundo: "THOSE are cheaper."<br><br>THESE = plural de THIS (coisas perto, na mão). THOSE = plural de THAT (coisas longe, na prateleira). É a mesma lógica: perto vs longe, só que agora são VÁRIAS coisas.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🍌",english:"These bananas look good. But those apples over there are cheaper.",portuguese:"Essas bananas parecem boas. Mas aquelas maçãs ali são mais baratas.",breakdown:"<strong>THESE</strong> = essas (NA MÃO). <strong>THOSE</strong> = aquelas (NA PRATELEIRA). Perto vs longe, plural."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"🛒",english:"Do we need these? Yes, grab those too — the big ones.",portuguese:"A gente precisa disso? Sim, pega aqueles também — os grandes.",breakdown:"<strong>THESE</strong> = esses (que temos). <strong>THOSE</strong> = aqueles (que estão lá). GRAB = pega."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"🏷️",english:"These are on sale! Two for five. Those are regular price.",portuguese:"Esses estão em promoção! Dois por cinco. Aqueles são preço normal.",breakdown:"<strong>THESE ARE</strong> = esses são/estão. <strong>THOSE ARE</strong> = aqueles são/estão. ON SALE = promoção."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"🥬",english:`Are those organic? I don't know — these say "organic" on the label.`,portuguese:'Aqueles são orgânicos? Sei não — esses dizem "orgânico" no rótulo.',breakdown:"<strong>ARE THOSE</strong> = aqueles são? (pergunta). THE LABEL = o rótulo."},{type:"rule",cardClass:"cyan",text:"<strong>THESE</strong> = plural de THIS (perto)",keyword:"THESE",keywordAfter:"Estes/Estas (várias coisas perto)"},{type:"rule",cardClass:"orange",text:"<strong>THOSE</strong> = plural de THAT (longe)",keyword:"THOSE",keywordAfter:"Aqueles/Aquelas (várias coisas longe)"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>THESE</strong> soa como "DÍIZ" (longo)<br><strong>THOSE</strong> soa como "DÔUZ"<br><br>Atenção ao som do TH!'},{type:"example",cardClass:"cyan",emoji:"📚",question:'<span class="hl-cyan">These</span> are my books.',questionTr:"Estes são meus livros.",answer:"(plural perto)",answerTr:"Várias coisas aqui"},{type:"example",cardClass:"orange",emoji:"🚗",question:'<span class="hl-orange">Those</span> are his cars.',questionTr:"Aqueles são os carros dele.",answer:"(plural longe)",answerTr:"Várias coisas lá"},{type:"examples",cardClass:"cyan",title:"👆 THESE - PERTO (plural)",items:[{emoji:"👟",en:'<span class="hl-cyan">These</span> shoes are mine.',pt:"Esses sapatos são meus."},{emoji:"🍎",en:'<span class="hl-cyan">These</span> apples are fresh.',pt:"Essas maçãs são frescas."},{emoji:"👥",en:'<span class="hl-cyan">These</span> people are nice.',pt:"Essas pessoas são legais."},{emoji:"🪑",en:'<span class="hl-cyan">These</span> chairs are new.',pt:"Essas cadeiras são novas."}]},{type:"examples",cardClass:"orange",title:"👉 THOSE - LONGE (plural)",items:[{emoji:"🏠",en:'<span class="hl-orange">Those</span> houses are old.',pt:"Aquelas casas são antigas."},{emoji:"🌳",en:'<span class="hl-orange">Those</span> trees are big.',pt:"Aquelas árvores são grandes."},{emoji:"📦",en:'<span class="hl-orange">Those</span> boxes are heavy.',pt:"Aquelas caixas são pesadas."},{emoji:"🎁",en:'<span class="hl-orange">Those</span> gifts are theirs.',pt:"Aqueles presentes são deles."}]},{type:"list",cardClass:"gold",title:"📊 QUADRO COMPLETO",items:[{emoji:"👆",text:"<strong>THIS</strong> → perto, singular"},{emoji:"👆",text:"<strong>THESE</strong> → perto, plural"},{emoji:"👉",text:"<strong>THAT</strong> → longe, singular"},{emoji:"👉",text:"<strong>THOSE</strong> → longe, plural"}]},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"This are my books.",leftNote:"THIS é singular",right:"These are my books.",rightNote:"THESE para plural",explanation:"Várias coisas = <strong>THESE/THOSE</strong> (com S)"},{type:"quiz",cardClass:"cyan",question:"🎯 Plural de THIS:",options:["That","Those","These"],correct:2},{type:"quiz",cardClass:"cyan",question:"🎯 Plural de THAT:",options:["These","Those","This"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete (vários livros na sua mão):",sentence:"_____ are my books.",correctWord:"These"},{type:"list",cardClass:"gold",title:"📝 RESUMO - THESE / THOSE",items:[{emoji:"👆",text:"<strong>THESE</strong> = estes/estas (perto, plural)"},{emoji:"👉",text:"<strong>THOSE</strong> = aqueles/aquelas (longe, plural)"},{emoji:"🔤",text:"Ambos terminam com S = plural"},{emoji:"⚠️",text:"Sempre com ARE (These ARE, Those ARE)"}]},{type:"end"}],vocabulary:[{emoji:"📚",pt:"Estes são meus livros",en:"These are my books"},{emoji:"🚗",pt:"Aqueles são os carros dele",en:"Those are his cars"},{emoji:"👟",pt:"Esses sapatos são seus",en:"These shoes are yours"},{emoji:"🏠",pt:"Aquelas casas são antigas",en:"Those houses are old"},{emoji:"👥",pt:"Essas pessoas são legais",en:"These people are nice"},{emoji:"🌳",pt:"Aquelas árvores são grandes",en:"Those trees are big"},{emoji:"🍎",pt:"Essas maçãs são vermelhas",en:"These apples are red"},{emoji:"📦",pt:"Aquelas caixas são pesadas",en:"Those boxes are heavy"},{emoji:"🪑",pt:"Essas cadeiras são novas",en:"These chairs are new"},{emoji:"🎁",pt:"Aqueles presentes são deles",en:"Those gifts are theirs"}]},{id:"is-are-questions",title:"IS / ARE (Questions)",emoji:"❓🔵",description:"Perguntas com IS/ARE",module:2,order:9,slides:[{type:"title",emoji:"❓🔵",title:"IS / ARE (Questions)",subtitle:"Fazer perguntas com TO BE"},{type:"situation",emoji:"🏥",cardClass:"cyan",text:'Você precisa marcar consulta e liga pro médico. A recepcionista faz mil perguntas: "IS the doctor available? ARE you a new patient? IS your insurance active?"<br><br>Em português, perguntar é fácil: muda a entonação e pronto. Em inglês, você precisa INVERTER: "You ARE ready" → "ARE you ready?" Essa inversão é a chave pra soar como pergunta de verdade.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"📞",english:"Hello, is the doctor available today?",portuguese:"Alô, o doutor está disponível hoje?",breakdown:'<strong>IS THE DOCTOR</strong> = o doutor está? Inverte: "The doctor IS" → "IS the doctor?"'},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"📋",english:"Are you a new patient? Yes, I am. Is that a problem?",portuguese:"Você é paciente novo? Sou sim. Isso é um problema?",breakdown:"<strong>ARE YOU</strong> = você é/está? Resposta curta: YES, I AM. / NO, I'M NOT."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"💳",english:"No problem. Is your insurance active? Are you on MassHealth?",portuguese:"Sem problema. Seu seguro tá ativo? Você tem MassHealth?",breakdown:"<strong>IS YOUR</strong> = seu... está? <strong>ARE YOU ON</strong> = você está no/tem? Perguntas de cadastro médico."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"📅",english:"Yes, I am. Is tomorrow OK? Are there any openings?",portuguese:"Sim. Amanhã tá bom? Tem algum horário?",breakdown:"<strong>IS TOMORROW OK</strong> = amanhã tá bom? <strong>ARE THERE</strong> = tem/existe? Pergunta pra horários."},{type:"rule",cardClass:"cyan",text:"Para perguntar, <strong>INVERTE</strong> a ordem!<br>O verbo vem ANTES do sujeito.",keyword:"IS/ARE + sujeito + ...?",keywordAfter:"Inversão = pergunta!"},{type:"tip",cardClass:"orange",icon:"🔄",title:"A REGRA DA INVERSÃO",text:"Afirmação: He <strong>is</strong> here.<br>Pergunta: <strong>Is</strong> he here?<br><br>Só inverte a posição!"},{type:"example",cardClass:"cyan",emoji:"👨",question:'<span class="hl-cyan">Is</span> he your brother?',questionTr:"Ele é seu irmão?",answer:"Yes, he is.",answerTr:"Sim, ele é."},{type:"example",cardClass:"green",emoji:"👥",question:'<span class="hl-green">Are</span> they ready?',questionTr:"Eles estão prontos?",answer:"Yes, they are.",answerTr:"Sim, estão."},{type:"example",cardClass:"cyan",emoji:"👋",question:'<span class="hl-cyan">Are</span> you okay?',questionTr:"Você está bem?",answer:"Yes, I'm fine.",answerTr:"Sim, estou bem."},{type:"examples",cardClass:"cyan",title:"❓ PERGUNTAS COM IS",items:[{emoji:"🏠",en:'<span class="hl-cyan">Is</span> she at home?',pt:"Ela está em casa?"},{emoji:"🌧️",en:'<span class="hl-cyan">Is</span> it raining?',pt:"Está chovendo?"},{emoji:"⏰",en:'<span class="hl-cyan">Is</span> it late?',pt:"É/Está tarde?"},{emoji:"📖",en:'<span class="hl-cyan">Is</span> this yours?',pt:"Isso é seu?"}]},{type:"examples",cardClass:"green",title:"❓ PERGUNTAS COM ARE",items:[{emoji:"👥",en:'<span class="hl-green">Are</span> they coming?',pt:"Eles estão vindo?"},{emoji:"👋",en:'<span class="hl-green">Are</span> you ready?',pt:"Você está pronto?"},{emoji:"🏠",en:'<span class="hl-green">Are</span> we late?',pt:"Estamos atrasados?"},{emoji:"📚",en:'<span class="hl-green">Are</span> these yours?',pt:"Esses são seus?"}]},{type:"tip",cardClass:"green",icon:"💡",title:"RESPOSTAS CURTAS",text:"Yes, I am. / No, I'm not.<br>Yes, he is. / No, he isn't.<br>Yes, they are. / No, they aren't.<br><br>Resposta curta = educada!"},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"You are okay?",leftNote:"Ordem de afirmação",right:"Are you okay?",rightNote:"Verbo antes = pergunta",explanation:"Em perguntas, o verbo vem <strong>ANTES</strong>!"},{type:"quiz",cardClass:"cyan",question:'🎯 "Você está bem?" em inglês:',options:["You are okay?","Are you okay?","Is you okay?"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Está chovendo?" em inglês:',options:["It is raining?","Is it raining?","Raining is it?"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete a pergunta:",sentence:"_____ he your friend?",correctWord:"Is"},{type:"list",cardClass:"gold",title:"📝 RESUMO - PERGUNTAS",items:[{emoji:"🔄",text:"Inverte: IS/ARE vem primeiro"},{emoji:"❓",text:"Is he...? / Are they...?"},{emoji:"✅",text:"Respostas: Yes, he is / No, he isn't"},{emoji:"⚠️",text:"Não esqueça de inverter!"}]},{type:"end"}],vocabulary:[{emoji:"👨",pt:"Ele é seu irmão?",en:"Is he your brother? / Is that your brother?"},{emoji:"👥",pt:"Eles estão prontos?",en:"Are they ready?"},{emoji:"👋",pt:"Você está bem?",en:"Are you okay? / Are you alright? / You okay?"},{emoji:"🏠",pt:"Ela está em casa?",en:"Is she at home?"},{emoji:"📖",pt:"Isso é seu?",en:"Is this yours?"},{emoji:"🎉",pt:"A festa é hoje?",en:"Is the party today?"},{emoji:"👩‍⚕️",pt:"Você é médico?",en:"Are you a doctor?"},{emoji:"🌧️",pt:"Está chovendo?",en:"Is it raining?"},{emoji:"⏰",pt:"É tarde?",en:"Is it late?"},{emoji:"✅",pt:"Está certo?",en:"Is it correct?"}]},{id:"is-are-negative",title:"IS / ARE (Negative)",emoji:"❌🔵",description:"Negação com IS/ARE",module:2,order:10,slides:[{type:"title",emoji:"❌🔵",title:"IS / ARE (Negative)",subtitle:"Negar com TO BE"},{type:"situation",emoji:"🚗",cardClass:"cyan",text:`Você pede um Uber e o motorista vai pro endereço errado. "This ISN'T the right street. We AREN'T late yet, but..."<br><br>Saber negar é tão importante quanto afirmar. ISN'T e AREN'T são as negativas que você vai ouvir e usar o dia todo. IS NOT → ISN'T. ARE NOT → AREN'T. Simples, rápido e essencial.`},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"📍",english:"Excuse me, this isn't the right address. I'm going to Main Street.",portuguese:"Com licença, esse não é o endereço certo. Vou pra Main Street.",breakdown:"<strong>ISN'T</strong> = is not = não é/está. Contração usada 99% do tempo na fala."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"📱",english:"Sorry! The GPS isn't working well. The roads aren't clear on the map.",portuguese:"Desculpa! O GPS não tá funcionando. As ruas não estão claras no mapa.",breakdown:"<strong>ISN'T WORKING</strong> = não está funcionando. <strong>AREN'T CLEAR</strong> = não estão claras. Plural = AREN'T."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"😌",english:"No problem. It isn't far. We aren't late yet.",portuguese:"Sem problema. Não é longe. Ainda não estamos atrasados.",breakdown:"<strong>IT ISN'T</strong> far = não é longe. <strong>WE AREN'T</strong> = nós não estamos. YET = ainda."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"🙌",english:"Here we are! That wasn't too bad. Thanks!",portuguese:"Chegamos! Não foi tão ruim. Obrigado!",breakdown:"<strong>WASN'T</strong> = was not = não foi/estava (passado de ISN'T). Bom pra comentar situações."},{type:"rule",cardClass:"red",text:"Para negar, adiciona <strong>NOT</strong> depois de IS/ARE.",keyword:"IS/ARE + NOT",keywordAfter:"Simples assim!"},{type:"tip",cardClass:"orange",icon:"⚡",title:"CONTRAÇÕES NEGATIVAS",text:"<strong>is not → isn't</strong><br><strong>are not → aren't</strong><br><strong>am not → I'm not</strong> (sem contração para AM)"},{type:"example",cardClass:"red",emoji:"👨",question:"He <span class='hl-red'>isn't</span> here.",questionTr:"Ele não está aqui.",answer:"(is + not = isn't)",answerTr:"Contração"},{type:"example",cardClass:"red",emoji:"👥",question:"They <span class='hl-red'>aren't</span> ready.",questionTr:"Eles não estão prontos.",answer:"(are + not = aren't)",answerTr:"Contração"},{type:"example",cardClass:"purple",emoji:"😴",question:"I<span class='hl-purple'>'m not</span> tired.",questionTr:"Eu não estou cansado.",answer:"(I am not)",answerTr:"Sem contração no AM"},{type:"examples",cardClass:"red",title:"❌ NEGAÇÕES COM ISN'T",items:[{emoji:"🏠",en:"She <span class='hl-red'>isn't</span> at home.",pt:"Ela não está em casa."},{emoji:"❄️",en:"It <span class='hl-red'>isn't</span> cold.",pt:"Não está frio."},{emoji:"⏰",en:"It <span class='hl-red'>isn't</span> late.",pt:"Não é tarde."},{emoji:"📖",en:"This <span class='hl-red'>isn't</span> mine.",pt:"Isso não é meu."}]},{type:"examples",cardClass:"red",title:"❌ NEGAÇÕES COM AREN'T",items:[{emoji:"👥",en:"They <span class='hl-red'>aren't</span> coming.",pt:"Eles não estão vindo."},{emoji:"👋",en:"You <span class='hl-red'>aren't</span> wrong.",pt:"Você não está errado."},{emoji:"🏠",en:"We <span class='hl-red'>aren't</span> late.",pt:"Não estamos atrasados."},{emoji:"📚",en:"These <span class='hl-red'>aren't</span> yours.",pt:"Esses não são seus."}]},{type:"tip",cardClass:"green",icon:"💡",title:"DUAS FORMAS",text:"Você pode dizer:<br><br><strong>He is not</strong> here. (formal)<br><strong>He isn't</strong> here. (comum)<br><br>Ambos estão corretos!"},{type:"comparison",cardClass:"red",title:"⚠️ CUIDADO COM I AM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"NÃO EXISTE",rightLabel:"CORRETO",left:"I amn't tired.",leftNote:"AMNT não existe!",right:"I'm not tired.",rightNote:"Use I'M NOT",explanation:`<strong>I AM NOT</strong> vira <strong>I'M NOT</strong> (nunca "amn't")`},{type:"quiz",cardClass:"cyan",question:'🎯 "Eu não estou cansado" em inglês:',options:["I amn't tired","I'm not tired","I aren't tired"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Ela não está em casa" em inglês:',options:["She not is at home","She isn't at home","She aren't at home"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete a negação:",sentence:"They _____ ready yet.",correctWord:"aren't"},{type:"list",cardClass:"gold",title:"📝 RESUMO - NEGAÇÃO",items:[{emoji:"❌",text:"<strong>IS NOT → ISN'T</strong>"},{emoji:"❌",text:"<strong>ARE NOT → AREN'T</strong>"},{emoji:"⚠️",text:`<strong>I AM NOT → I'M NOT</strong> (não "amn't")`},{emoji:"✅",text:"Formal: is not / Comum: isn't"}]},{type:"end"}],vocabulary:[{emoji:"👨",pt:"Ele não está aqui",en:"He isn't here / He is not here / He's not here"},{emoji:"👥",pt:"Eles não estão prontos",en:"They aren't ready"},{emoji:"😴",pt:"Eu não estou cansado",en:"I'm not tired"},{emoji:"🏠",pt:"Ela não está em casa",en:"She isn't at home"},{emoji:"📖",pt:"Isso não é meu",en:"This isn't mine"},{emoji:"❄️",pt:"Não está frio",en:"It isn't cold"},{emoji:"⏰",pt:"Não é tarde",en:"It isn't late"},{emoji:"🌧️",pt:"Não está chovendo",en:"It isn't raining"},{emoji:"✅",pt:"Não está certo",en:"It isn't correct"},{emoji:"🆓",pt:"Não é grátis",en:"It isn't free"}]},{id:"when",title:"WHEN",emoji:"⏰❓",description:"Perguntar tempo",module:2,order:11,slides:[{type:"title",emoji:"⏰❓",title:"WHEN",subtitle:"Perguntar sobre tempo"},{type:"situation",emoji:"💼",cardClass:"cyan",text:'Você conseguiu uma entrevista numa empresa de limpeza. A gerente pergunta: "WHEN can you start? WHEN are you available?"<br><br>No trabalho, WHEN é a pergunta que decide se você ganha o emprego ou não. Quando começa? Quando pode? Quando recebe? Se você não entende WHEN, perde oportunidade. Se sabe usar, demonstra que é profissional.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"💼",english:"When can you start? I can start Monday.",portuguese:"Quando pode começar? Posso começar segunda.",breakdown:"<strong>WHEN CAN YOU</strong> = quando você pode? Pergunta clássica de entrevista."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"🌙",english:"Good. When are you available? Mornings or nights?",portuguese:"Bom. Quando você está disponível? Manhã ou noite?",breakdown:"<strong>WHEN ARE YOU</strong> = quando você está? AVAILABLE = disponível."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"⏰",english:"Nights are better. When does the shift end? At midnight.",portuguese:"Noite é melhor. Quando acaba o turno? À meia-noite.",breakdown:"<strong>WHEN DOES</strong> = quando (ele/ela/isso)? SHIFT = turno. AT midnight = à meia-noite."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"💰",english:"When do I get paid? Every Friday, direct deposit.",portuguese:"Quando eu recebo? Toda sexta, depósito direto.",breakdown:"<strong>WHEN DO I GET PAID</strong> = quando eu recebo? GET PAID = receber pagamento. Pergunta essencial!"},{type:"rule",cardClass:"cyan",text:"Quando você quer saber <strong>QUANDO</strong> algo acontece:",keyword:"WHEN",keywordAfter:"Sempre sobre TEMPO!"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>WHEN</strong> soa como "UÉN"<br><br>Bem parecido com WHERE, mas termina em "N"'},{type:"example",cardClass:"cyan",emoji:"📅",question:'<span class="hl-cyan">When</span> is the meeting?',questionTr:"Quando é a reunião?",questionUse:"Use pra perguntar quando algo vai acontecer (dia/horário).",answer:"At 3 PM.",answerTr:"Às 15h.",answerUse:"<strong>At</strong> = hora exata (At 3 PM / At noon)."},{type:"example",cardClass:"cyan",emoji:"✈️",question:'<span class="hl-cyan">When</span> did you arrive?',questionTr:"Quando você chegou?",questionUse:"Passado: use DID + verbo base (arrive, não arrived).",answer:"Yesterday.",answerTr:"Ontem.",answerUse:"Respostas rápidas: yesterday / last night / this morning."},{type:"example",cardClass:"cyan",emoji:"🎂",question:'<span class="hl-cyan">When</span> is your birthday?',questionTr:"Quando é seu aniversário?",questionUse:"Use pra perguntar data (dia/mês/ano).",answer:"In July.",answerTr:"Em julho.",answerUse:"<strong>In</strong> = mês ou ano (In July / In 2026)."},{type:"examples",cardClass:"green",title:"📆 TIPOS DE RESPOSTAS",items:[{emoji:"⏰",en:"At 3 PM / At noon / At night",pt:"Às 3h / Ao meio-dia / À noite",use:"AT = ponto no tempo. Pense como um alfinete no relógio."},{emoji:"📅",en:"On Monday / On the 15th",pt:"Na segunda / No dia 15",use:"ON = em cima do dia. Monday, Tuesday... sempre com ON."},{emoji:"📆",en:"In July / In 2024 / In the morning",pt:"Em julho / Em 2024 / De manhã",use:"IN = dentro de um período maior (mês, ano, estação)."},{emoji:"⏳",en:"Tomorrow / Next week / Soon",pt:"Amanhã / Semana que vem / Em breve",use:"Essas palavras NÃO precisam de at/on/in. Vão sozinhas!"}]},{type:"examples",cardClass:"purple",title:"⏪ WHEN NO PASSADO",items:[{emoji:"✈️",en:'When <span class="hl-purple">did</span> you arrive?',pt:"Quando você chegou?",use:"Passado: DID + verbo base (arrive, não arrived)."},{emoji:"📞",en:'When <span class="hl-purple">did</span> she call?',pt:"Quando ela ligou?",use:"DID + verbo base (call, não called). O DID já marca o passado."},{emoji:"🏠",en:'When <span class="hl-purple">did</span> you move here?',pt:"Quando você se mudou pra cá?",use:"Pergunta super comum entre brasileiros nos EUA."}]},{type:"comparison",cardClass:"cyan",title:"⏰ WHEN vs WHAT TIME",leftClass:"left-side",rightClass:"right-side",leftIcon:"📅",rightIcon:"⏰",leftLabel:"WHEN (geral)",rightLabel:"WHAT TIME (específico)",left:'<span class="hl-cyan">When</span> is the party?',leftNote:"Pode ser dia, mês, horário...",right:'<span class="hl-purple">What time</span> is the party?',rightNote:"Quer saber o horário exato",explanation:"Ambos funcionam, mas WHAT TIME é mais específico sobre horas"},{type:"tip",cardClass:"gold",icon:"💡",title:"DICA PRÁTICA",text:`No dia a dia americano, é comum ouvir:<br><br><strong>"When's the meeting?"</strong><br><br>É a contração de "When is"`},{type:"quiz",cardClass:"cyan",question:"🎯 Para saber o horário de algo, uso:",options:["WHERE","WHEN","WHAT"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Quando você chegou?" em inglês:',options:["When you arrived?","When did you arrive?","When are you arrive?"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete a pergunta:",sentence:"_____ is the meeting?",correctWord:"When"},{type:"list",cardClass:"gold",title:"📝 RESUMO - WHEN",items:[{emoji:"⏰",text:"<strong>WHEN</strong> = quando"},{emoji:"📅",text:"Respostas: at (hora), on (dia), in (mês/ano)"},{emoji:"🗣️",text:'Pronúncia: "UÉN"'},{emoji:"💡",text:"Contração comum: When's = When is"}]},{type:"end"}],vocabulary:[{emoji:"📅",pt:"Quando é a reunião?",en:"When is the meeting?",level:1},{emoji:"✈️",pt:"Quando você chegou?",en:"When did you arrive?",level:1},{emoji:"🎂",pt:"Quando é seu aniversário?",en:"When is your birthday?",level:1},{emoji:"🏠",pt:"Quando você volta?",en:"When are you coming back?",level:2},{emoji:"🎬",pt:"Quando começa o filme?",en:"When does the movie start?",level:2},{emoji:"💼",pt:"Quando você começa?",en:"When do you start?",level:1},{emoji:"🏥",pt:"Quando é a consulta?",en:"When is the appointment?",level:1},{emoji:"🍽️",pt:"Quando é o jantar?",en:"When is dinner?",level:1},{emoji:"📞",pt:"Quando posso ligar?",en:"When can I call?",level:1},{emoji:"🚌",pt:"Quando sai o ônibus?",en:"When does the bus leave?",level:2},{emoji:"🌅",pt:"Quando abre?",en:"When does it open?",level:1},{emoji:"🌙",pt:"Quando fecha?",en:"When does it close?",level:1},{emoji:"🚌",pt:"Quando passa o ônibus?",en:"When does the bus come?",level:1},{emoji:"🏢",pt:"Quando você trabalha?",en:"When do you work?",level:1},{emoji:"📅",pt:"Quando foi isso?",en:"When was that?",level:1},{emoji:"🚀",pt:"Quando começa?",en:"When does it start?",level:1},{emoji:"🏁",pt:"Quando termina?",en:"When does it end?",level:1},{emoji:"✈️",pt:"Quando você viaja?",en:"When are you traveling?",level:1},{emoji:"🎓",pt:"Quando é a formatura?",en:"When is graduation?",level:2},{emoji:"💍",pt:"Quando você casou?",en:"When did you get married?",level:2},{emoji:"🎉",pt:"Quando é a festa?",en:"When is the party?",level:2}]},{id:"why",title:"WHY",emoji:"🤷❓",description:'Perguntar "por quê"',module:2,order:12,slides:[{type:"title",emoji:"🤷❓",title:"WHY",subtitle:'Perguntar "por quê"'},{type:"situation",emoji:"🏗️",cardClass:"cyan",text:'O contractor olha a cozinha inacabada e pergunta: "WHY is this not finished?" Você precisa explicar.<br><br>WHY é a pergunta que cobra explicação. No trabalho, no dia a dia, na escola do seu filho — todo mundo vai te perguntar WHY em algum momento. E você precisa saber responder. A boa notícia: a resposta quase sempre começa com BECAUSE (próxima aula).'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"😤",english:"Carlos, why is the kitchen not finished?",portuguese:"Carlos, por que a cozinha não está pronta?",breakdown:"<strong>WHY IS</strong> = por que está? O chefe quer uma explicação. Fique calmo e responda."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"📦",english:"The tiles arrived late. Why? I don't know — ask the supplier.",portuguese:"Os pisos chegaram atrasados. Por quê? Não sei — pergunta pro fornecedor.",breakdown:"<strong>WHY?</strong> sozinho = por quê? Pode usar só WHY como pergunta curta."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"📞",english:"Why didn't you call me? I tried! Your phone was off.",portuguese:"Por que não me ligou? Tentei! Seu celular tava desligado.",breakdown:"<strong>WHY DIDN'T YOU</strong> = por que você não? DIDN'T = passado negativo. I TRIED = eu tentei."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"💡",english:"OK, why not finish tomorrow morning? Good idea, boss.",portuguese:"OK, por que não termina amanhã cedo? Boa ideia, chefe.",breakdown:"<strong>WHY NOT</strong> = por que não? Forma de sugerir algo. Super útil no trabalho."},{type:"rule",cardClass:"cyan",text:"Quando você quer saber o <strong>MOTIVO</strong> de algo:",keyword:"WHY",keywordAfter:"Sempre sobre RAZÃO!"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>WHY</strong> soa como "UAI"<br><br>Igual ao "uai" mineiro! 😄'},{type:"example",cardClass:"cyan",emoji:"😢",question:'<span class="hl-cyan">Why</span> are you sad?',questionTr:"Por que você está triste?",questionUse:"Use pra perguntar o motivo de uma emoção.",answer:"Because I miss home.",answerTr:"Porque sinto saudade de casa.",answerUse:"Responda com <strong>Because...</strong> + frase."},{type:"example",cardClass:"cyan",emoji:"⏰",question:'<span class="hl-cyan">Why</span> are you late?',questionTr:"Por que você está atrasado?",questionUse:"Use pra perguntar o motivo de algo (razão).",answer:"Because of traffic.",answerTr:"Por causa do trânsito.",answerUse:"<strong>Because of</strong> + coisa (traffic, rain, work)."},{type:"example",cardClass:"cyan",emoji:"🚫",question:'<span class="hl-cyan">Why</span> not?',questionTr:"Por que não?",questionUse:'Resposta curta quando alguém diz "não" ou recusa algo.',answer:"Let's do it!",answerTr:"Vamos fazer!",answerUse:"Let's = let us = vamos! Expressão de entusiasmo."},{type:"examples",cardClass:"cyan",title:"🤔 PERGUNTAS COM WHY",items:[{emoji:"💼",en:'<span class="hl-cyan">Why</span> do you work here?',pt:"Por que você trabalha aqui?",use:"Perguntando o motivo de trabalhar num lugar específico."},{emoji:"😴",en:'<span class="hl-cyan">Why</span> are you tired?',pt:"Por que você está cansado?",use:"Perguntando o motivo do cansaço."},{emoji:"📞",en:'<span class="hl-cyan">Why</span> did you call?',pt:"Por que você ligou?",use:"Passado: DID + verbo base (call, não called)."},{emoji:"🏃",en:'<span class="hl-cyan">Why</span> are you running?',pt:"Por que você está correndo?",use:"Perguntando por que alguém está correndo/com pressa."}]},{type:"tip",cardClass:"green",icon:"💡",title:"WHY NOT = POR QUE NÃO?",text:'<strong>"Why not?"</strong> é super comum!<br><br>Usado para aceitar sugestões:<br>"Wanna grab coffee?" → "Why not!"'},{type:"comparison",cardClass:"cyan",title:"❓ WHY vs BECAUSE",leftClass:"left-side",rightClass:"right-side",leftIcon:"❓",rightIcon:"💡",leftLabel:"WHY (pergunta)",rightLabel:"BECAUSE (resposta)",left:'<span class="hl-cyan">Why</span> are you here?',leftNote:"Perguntando o motivo",right:'<span class="hl-green">Because</span> I need help.',rightNote:"Dando o motivo",explanation:"<strong>WHY</strong> pergunta → <strong>BECAUSE</strong> responde"},{type:"examples",cardClass:"purple",title:"⏪ WHY NO PASSADO",items:[{emoji:"🏠",en:'<span class="hl-cyan">Why</span> <span class="hl-purple">did</span> you leave?',pt:"Por que você saiu?",use:"Perguntando por que alguém saiu. DID + leave (base)."},{emoji:"📞",en:`<span class="hl-cyan">Why</span> <span class="hl-purple">didn't</span> you call?`,pt:"Por que você não ligou?",use:`DIDN'T = negativo no passado. "Por que NÃO ligou?"`},{emoji:"🤔",en:'<span class="hl-cyan">Why</span> <span class="hl-purple">did</span> this happen?',pt:"Por que isso aconteceu?",use:"Perguntando por que algo aconteceu."}]},{type:"comparison",cardClass:"red",title:"⚠️ CUIDADO",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"PORTUGUÊS",rightLabel:"INGLÊS",left:"Por que? / Porque",leftNote:"Mesmo som, escrita diferente",right:"Why? / Because",rightNote:"Palavras completamente diferentes",explanation:"Em inglês, pergunta e resposta são palavras diferentes!"},{type:"quiz",cardClass:"cyan",question:"🎯 Para perguntar o motivo, uso:",options:["WHAT","WHY","HOW"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Por que você está aqui?" em inglês:',options:["Why you are here?","Why are you here?","Because you are here?"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete a pergunta:",sentence:"_____ are you late?",correctWord:"Why"},{type:"list",cardClass:"gold",title:"📝 RESUMO - WHY",items:[{emoji:"🤷",text:"<strong>WHY</strong> = por que (pergunta)"},{emoji:"💡",text:"Resposta: BECAUSE"},{emoji:"🗣️",text:'Pronúncia: "UAI"'},{emoji:"👍",text:'"Why not?" = aceitar sugestão'}]},{type:"end"}],vocabulary:[{emoji:"😢",pt:"Por que você está triste?",en:"Why are you sad? / Why are you upset?"},{emoji:"⏰",pt:"Por que está atrasado?",en:"Why are you late?"},{emoji:"🚫",pt:"Por que não?",en:"Why not?"},{emoji:"🏠",pt:"Por que você foi?",en:"Why did you go?"},{emoji:"💼",pt:"Por que você trabalha aqui?",en:"Why do you work here?"},{emoji:"🍕",pt:"Por que você gosta disso?",en:"Why do you like this?"},{emoji:"📞",pt:"Por que você ligou?",en:"Why did you call?"},{emoji:"😴",pt:"Por que está cansado?",en:"Why are you tired?"},{emoji:"🤔",pt:"Por que isso aconteceu?",en:"Why did this happen?"},{emoji:"❓",pt:"Por que pergunta?",en:"Why do you ask?"}]},{id:"because",title:"BECAUSE",emoji:"💡➡️",description:'Responder "porque"',module:2,order:13,slides:[{type:"title",emoji:"💡➡️",title:"BECAUSE",subtitle:"Dar o motivo"},{type:"situation",emoji:"🏫",cardClass:"cyan",text:'Reunião na escola. A professora pergunta por que seu filho faltou. "BECAUSE he was sick." Por que o inglês dele melhorou? "BECAUSE he practices every day."<br><br>BECAUSE é a resposta do WHY. Funciona como "porque" em português. A estrutura é idêntica: WHY...? → BECAUSE + motivo. Dominar esse par WHY/BECAUSE é essencial pra se explicar em qualquer situação.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🏫",english:"Why was Lucas absent Monday? Because he was sick.",portuguese:"Por que o Lucas faltou segunda? Porque estava doente.",breakdown:"<strong>BECAUSE</strong> = porque (resposta). WHY...? → BECAUSE + motivo. Sempre juntos."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"💊",english:"He's better now because he took medicine.",portuguese:"Ele tá melhor agora porque tomou remédio.",breakdown:"BECAUSE no MEIO da frase = porque. Conecta duas ideias: resultado + motivo."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"📱",english:"His English is improving because he practices at home.",portuguese:"O inglês dele tá melhorando porque pratica em casa.",breakdown:"<strong>IS IMPROVING</strong> = está melhorando. <strong>BECAUSE HE PRACTICES</strong> = porque ele pratica. Motivo do progresso!"},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"😊",english:"That's great! I'm happy because he's a good student.",portuguese:"Que bom! Fico feliz porque ele é um bom aluno.",breakdown:"<strong>I'M HAPPY BECAUSE</strong> = fico feliz porque. BECAUSE explica o sentimento."},{type:"rule",cardClass:"green",text:"Para responder uma pergunta com <strong>WHY</strong>:",keyword:"BECAUSE",keywordAfter:"Dá a razão/motivo!"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>BECAUSE</strong> soa como "BICÓZ"<br><br>No dia a dia, vira "cause" ou "cuz"'},{type:"example",cardClass:"green",emoji:"😢",question:"Why are you sad?",questionTr:"Por que você está triste?",questionUse:"Perguntando o motivo de uma emoção.",answer:'<span class="hl-green">Because</span> I miss home.',answerTr:"Porque sinto saudade.",answerUse:"<strong>Because + frase</strong> (sujeito + verbo). Miss = sentir falta."},{type:"example",cardClass:"green",emoji:"⏰",question:"Why are you late?",questionTr:"Por que está atrasado?",questionUse:"Perguntando por que alguém se atrasou.",answer:'<span class="hl-green">Because</span> of traffic.',answerTr:"Por causa do trânsito.",answerUse:"<strong>Because of + coisa</strong> (substantivo, não frase)."},{type:"example",cardClass:"green",emoji:"😴",question:"Why are you tired?",questionTr:"Por que está cansado?",questionUse:"Perguntando por que alguém está cansado.",answer:"<span class='hl-green'>Because</span> I didn't sleep.",answerTr:"Porque não dormi.",answerUse:"Passado negativo: <strong>didn't</strong> + verbo base (sleep)."},{type:"comparison",cardClass:"cyan",title:"📝 BECAUSE vs BECAUSE OF",leftClass:"left-side",rightClass:"right-side",leftIcon:"📝",rightIcon:"📦",leftLabel:"BECAUSE + frase",rightLabel:"BECAUSE OF + coisa",left:"<span class='hl-cyan'>Because</span> I'm tired.",leftNote:"Seguido de sujeito + verbo",right:"<span class='hl-purple'>Because of</span> the rain.",rightNote:"Seguido de substantivo",explanation:"<strong>BECAUSE</strong> + frase completa<br><strong>BECAUSE OF</strong> + substantivo"},{type:"examples",cardClass:"green",title:"✅ RESPOSTAS COMUNS",items:[{emoji:"💼",en:'<span class="hl-green">Because</span> I need to work.',pt:"Porque preciso trabalhar.",use:"BECAUSE + frase completa (sujeito + verbo)."},{emoji:"❤️",en:'<span class="hl-green">Because</span> I love you.',pt:"Porque eu te amo.",use:"Expressão de amor/carinho. Muito usada no dia a dia."},{emoji:"⏰",en:"<span class='hl-green'>Because</span> it's late.",pt:"Porque é tarde.",use:"Resposta curta e direta. It's = it is."},{emoji:"😋",en:"<span class='hl-green'>Because</span> it's delicious.",pt:"Porque é gostoso.",use:"Delicious = delicioso. Boa pra elogiar comida!"}]},{type:"examples",cardClass:"purple",title:"📦 BECAUSE OF + COISA",items:[{emoji:"🚗",en:'<span class="hl-purple">Because of</span> the traffic.',pt:"Por causa do trânsito.",use:"A desculpa mais usada nos EUA! Traffic = trânsito."},{emoji:"☔",en:'<span class="hl-purple">Because of</span> the rain.',pt:"Por causa da chuva.",use:"Rain = chuva. Também: snow (neve), storm (tempestade)."},{emoji:"👤",en:'<span class="hl-purple">Because of</span> you.',pt:"Por sua causa.",use:'"Por sua causa" — pode ser positivo ou negativo, depende do tom.'},{emoji:"💼",en:'<span class="hl-purple">Because of</span> work.',pt:"Por causa do trabalho.",use:'Sem "the" antes de work quando é conceito geral.'}]},{type:"tip",cardClass:"gold",icon:"💡",title:"VERSÃO CURTA",text:`No inglês informal, BECAUSE vira:<br><br><strong>'cause</strong> ou <strong>cuz</strong><br><br>"I'm late 'cause of traffic."`},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"Because of I'm tired.",leftNote:"OF + frase não funciona",right:"Because I'm tired.",rightNote:"Sem OF antes de frase",explanation:"<strong>BECAUSE OF</strong> só com substantivos!"},{type:"quiz",cardClass:"cyan",question:"🎯 Para responder WHY, uso:",options:["WHY","BECAUSE","WHAT"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Por causa da chuva" em inglês:',options:["Because the rain","Because of the rain","Because is rain"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete a resposta:",sentence:"Why are you happy? _____ it's my birthday!",correctWord:"Because"},{type:"list",cardClass:"gold",title:"📝 RESUMO - BECAUSE",items:[{emoji:"💡",text:"<strong>BECAUSE</strong> = porque (resposta)"},{emoji:"📦",text:"<strong>BECAUSE OF</strong> + substantivo"},{emoji:"🗣️",text:'Pronúncia: "BICÓZ" (ou "cuz")'},{emoji:"🔗",text:"WHY pergunta → BECAUSE responde"}]},{type:"end"}],vocabulary:[{emoji:"💡",pt:"Porque eu quero",en:"Because I want to",level:1},{emoji:"🚗",pt:"Por causa do trânsito",en:"Because of traffic",level:1},{emoji:"😴",pt:"Porque estou cansado",en:"Because I'm tired"},{emoji:"🤒",pt:"Porque estou doente",en:"Because I'm sick"},{emoji:"💼",pt:"Porque preciso trabalhar",en:"Because I need to work",level:2},{emoji:"❤️",pt:"Porque eu te amo",en:"Because I love you",level:1},{emoji:"⏰",pt:"Porque é tarde",en:"Because it's late"},{emoji:"☔",pt:"Por causa da chuva",en:"Because of the rain",level:1},{emoji:"💰",pt:"Porque é barato",en:"Because it's cheap"},{emoji:"😋",pt:"Porque é gostoso",en:"Because it's delicious"}]},{id:"how",title:"HOW",emoji:"🔧❓",description:'Perguntar "como"',module:2,order:14,slides:[{type:"title",emoji:"🔧❓",title:"HOW",subtitle:'Perguntar "como"'},{type:"situation",emoji:"🎉",cardClass:"cyan",text:'Seu vizinho americano te convida pro BBQ. Você experimenta a costela: "HOW do you make this?!" Ele ri e explica. Você pergunta: "HOW long do you cook it?"<br><br>HOW é a pergunta mais versátil do inglês. Como faz? Como tá? Quanto tempo? HOW do you...? HOW is it? HOW long? HOW much? Domine HOW e você consegue perguntar praticamente qualquer coisa.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🥩",english:"How do you make this? It smells amazing!",portuguese:"Como você faz isso? O cheiro tá incrível!",breakdown:"<strong>HOW DO YOU MAKE</strong> = como você faz? HOW + DO/DOES + sujeito + verbo."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"⏱️",english:"Easy! How long do you cook it? About 20 minutes per side.",portuguese:"Fácil! Quanto tempo cozinha? Uns 20 minutos de cada lado.",breakdown:"<strong>HOW LONG</strong> = quanto tempo? PER SIDE = de cada lado. HOW + adjetivo = muito versátil."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"😋",english:"How is it? Delicious! How did you learn this?",portuguese:"Tá como? Delicioso! Como aprendeu?",breakdown:"<strong>HOW IS IT</strong> = como está? (pedindo opinião). <strong>HOW DID YOU</strong> = como você fez? (passado)."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"🔥",english:"YouTube! Hey, how about a Brazilian BBQ next time?",portuguese:"YouTube! E que tal um churrasco brasileiro na próxima?",breakdown:"<strong>HOW ABOUT</strong> = que tal? Forma casual de sugerir algo. Super útil entre amigos!"},{type:"rule",cardClass:"cyan",text:"Quando você quer saber o <strong>MODO</strong> de fazer algo:",keyword:"HOW",keywordAfter:"A pergunta mais útil!"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>HOW</strong> soa como "RÁU"<br><br>Parece "now" mas começa com H'},{type:"example",cardClass:"cyan",emoji:"👋",question:'<span class="hl-cyan">How</span> are you?',questionTr:"Como você está?",questionUse:"Cumprimento do dia a dia (super comum). Nem sempre espera resposta real.",answer:"I'm fine, thanks!",answerTr:"Estou bem, obrigado!",answerUse:"Responda curto e devolva: <strong>And you?</strong>"},{type:"example",cardClass:"cyan",emoji:"🔧",question:'<span class="hl-cyan">How</span> do I do this?',questionTr:"Como faço isso?",questionUse:"Perguntar como fazer algo (passo/jeito). Essencial no trabalho.",answer:"Like this.",answerTr:"Assim.",answerUse:"Like this = assim. Pode pedir: <strong>Can you show me?</strong>"},{type:"example",cardClass:"cyan",emoji:"🗣️",question:'<span class="hl-cyan">How</span> do you say "obrigado"?',questionTr:'Como se diz "obrigado"?',questionUse:"Perguntar tradução. Frase salvadora pra quem está aprendendo!",answer:"Thank you.",answerTr:"Thank you.",answerUse:"Padrão: <strong>How do you say</strong> + palavra/frase?"},{type:"examples",cardClass:"cyan",title:"🔧 PERGUNTAS ÚTEIS",items:[{emoji:"🚗",en:'<span class="hl-cyan">How</span> do I get there?',pt:"Como chego lá?",use:"Pedindo direções. Resposta pode ser: take a left, go straight..."},{emoji:"✍️",en:'<span class="hl-cyan">How</span> do you spell that?',pt:"Como se escreve isso?",use:"Pra pedir pra soletrar. Essencial pra nomes e endereços."},{emoji:"📞",en:'<span class="hl-cyan">How</span> can I help?',pt:"Como posso ajudar?",use:"Oferecendo ajuda. Muito educado e profissional."},{emoji:"🍳",en:'<span class="hl-cyan">How</span> do you make this?',pt:"Como faz isso?",use:"Pedindo instrução/receita. Make = fazer/criar."}]},{type:"tip",cardClass:"green",icon:"💡",title:"HOW ARE YOU?",text:`A pergunta mais comum do inglês!<br><br>Respostas: "I'm fine" / "Good" / "Not bad"<br><br>Sempre pergunte de volta: "And you?"`},{type:"examples",cardClass:"purple",title:"⏪ HOW NO PASSADO",items:[{emoji:"💼",en:'<span class="hl-cyan">How</span> <span class="hl-purple">was</span> work?',pt:"Como foi o trabalho?",use:'Pergunta do dia a dia. Responda: "It was good / busy / tiring."'},{emoji:"🎬",en:'<span class="hl-cyan">How</span> <span class="hl-purple">was</span> the movie?',pt:"Como foi o filme?",use:"Pra pedir opinião sobre algo que já aconteceu."},{emoji:"✈️",en:'<span class="hl-cyan">How</span> <span class="hl-purple">was</span> your trip?',pt:"Como foi sua viagem?",use:"WAS = passado de IS. Pra coisas singulares (trip, movie, day)."},{emoji:"📝",en:'<span class="hl-cyan">How</span> <span class="hl-purple">did</span> it go?',pt:"Como foi?",use:'Pergunta genérica super usada. "How did the interview go?"'}]},{type:"list",cardClass:"cyan",title:"🔗 HOW + OUTRAS PALAVRAS",items:[{emoji:"💰",text:"<strong>HOW MUCH</strong> = quanto (preço/quantidade)"},{emoji:"🔢",text:"<strong>HOW MANY</strong> = quantos (contáveis)"},{emoji:"⏰",text:"<strong>HOW LONG</strong> = quanto tempo"},{emoji:"📏",text:"<strong>HOW FAR</strong> = quão longe"},{emoji:"👴",text:"<strong>HOW OLD</strong> = quantos anos"}]},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"How I do this?",leftNote:"Faltou o auxiliar",right:"How do I do this?",rightNote:"Com DO antes do sujeito",explanation:"Em perguntas: <strong>HOW + DO/DOES/DID + sujeito</strong>"},{type:"quiz",cardClass:"cyan",question:'🎯 "Como você está?" em inglês:',options:["How you are?","How are you?","How is you?"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Como foi o trabalho?" em inglês:',options:["How is work?","How was work?","How did work?"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete a pergunta:",sentence:"_____ do I get to the airport?",correctWord:"How"},{type:"list",cardClass:"gold",title:"📝 RESUMO - HOW",items:[{emoji:"🔧",text:"<strong>HOW</strong> = como"},{emoji:"👋",text:"Mais comum: How are you?"},{emoji:"🗣️",text:'Pronúncia: "RÁU"'},{emoji:"🔗",text:"Combinações: how much, how many, how long..."}]},{type:"end"}],vocabulary:[{emoji:"👋",pt:"Como você está?",en:"How are you? / How are you doing? / How's it going?"},{emoji:"🔧",pt:"Como faço isso?",en:"How do I do this?"},{emoji:"🗣️",pt:"Como se diz?",en:"How do you say...?"},{emoji:"✍️",pt:"Como se escreve?",en:"How do you spell...?"},{emoji:"🚗",pt:"Como chego lá?",en:"How do I get there?"},{emoji:"💼",pt:"Como foi o trabalho?",en:"How was work?"},{emoji:"🎬",pt:"Como foi o filme?",en:"How was the movie?"},{emoji:"📞",pt:"Como posso ajudar?",en:"How can I help?"},{emoji:"🍳",pt:"Como faz isso?",en:"How do you make this?"},{emoji:"⏰",pt:"Quanto tempo leva?",en:"How long does it take?"}]},{id:"here-there-over",title:"HERE / THERE / OVER THERE",emoji:"📍👉🏔️",description:"Aqui / Ali / Lá",module:2,order:15,slides:[{type:"title",emoji:"📍👉🏔️",title:"HERE / THERE / OVER THERE",subtitle:"Graus de distância"},{type:"situation",emoji:"📦",cardClass:"cyan",text:'Você faz delivery num warehouse. O supervisor aponta: "Small packages HERE, next to me. Big ones THERE, by the door. Returns go OVER THERE, in the back."<br><br>Inglês tem 3 níveis de distância: HERE (aqui, perto de mim), THERE (ali, perto de você), OVER THERE (lá longe). Em português a gente mistura "ali" e "lá". Em inglês, a diferença importa — especialmente quando alguém te dá instrução no trabalho.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"📍",english:"Put the small packages here, next to me.",portuguese:"Coloca os pacotes pequenos aqui, do meu lado.",breakdown:"<strong>HERE</strong> = aqui, perto de MIM. NEXT TO ME = do meu lado. Nível 1 de distância."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"🚪",english:"The big ones go there, by the door.",portuguese:"Os grandes vão ali, perto da porta.",breakdown:"<strong>THERE</strong> = ali, perto de VOCÊ ou a meia distância. BY THE DOOR = perto da porta. Nível 2."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"🏠",english:"And the returns? Put them over there, in the back room.",portuguese:"E as devoluções? Coloca lá, na sala dos fundos.",breakdown:"<strong>OVER THERE</strong> = lá longe. IN THE BACK = nos fundos. Nível 3 — mais longe de todos."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"✅",english:"Got it! Here, there, over there. Easy!",portuguese:"Entendi! Aqui, ali, lá. Fácil!",breakdown:"3 níveis: <strong>HERE</strong> (perto de mim) → <strong>THERE</strong> (ali) → <strong>OVER THERE</strong> (lá longe). Como em português!"},{type:"rule",cardClass:"cyan",text:"Três níveis de distância:",keyword:"HERE → THERE → OVER THERE",keywordAfter:"Aqui → Ali → Lá"},{type:"tip",cardClass:"gold",icon:"📏",title:"DISTÂNCIA",text:"<strong>HERE</strong> = AQUI (perto de você)<br><strong>THERE</strong> = ALI (médio, visível)<br><strong>OVER THERE</strong> = LÁ (longe)"},{type:"example",cardClass:"green",emoji:"📍",question:"It's <span class='hl-green'>here</span>.",questionTr:"É aqui.",answer:"(HERE = aqui)",answerTr:"Perto de você"},{type:"example",cardClass:"orange",emoji:"👉",question:"It's <span class='hl-orange'>there</span>.",questionTr:"É ali.",answer:"(THERE = ali)",answerTr:"Distância média"},{type:"example",cardClass:"red",emoji:"🏔️",question:"It's <span class='hl-red'>over there</span>.",questionTr:"É lá.",answer:"(OVER THERE = lá)",answerTr:"Longe"},{type:"examples",cardClass:"green",title:"📍 HERE = AQUI",items:[{emoji:"📍",en:"<span class='hl-green'>Here</span>",pt:"Aqui"},{emoji:"📍",en:"Right <span class='hl-green'>here</span>",pt:"Bem aqui"},{emoji:"📍",en:"Around <span class='hl-green'>here</span>",pt:"Por aqui"},{emoji:"👋",en:"Come <span class='hl-green'>here</span>",pt:"Vem aqui"}]},{type:"examples",cardClass:"orange",title:"👉 THERE = ALI",items:[{emoji:"👉",en:"<span class='hl-orange'>There</span>",pt:"Ali"},{emoji:"👉",en:"Right <span class='hl-orange'>there</span>",pt:"Bem ali"},{emoji:"🚶",en:"Go <span class='hl-orange'>there</span>",pt:"Vai ali"},{emoji:"👀",en:"Look <span class='hl-orange'>there</span>",pt:"Olha ali"}]},{type:"examples",cardClass:"red",title:"🏔️ OVER THERE = LÁ",items:[{emoji:"🏔️",en:"<span class='hl-red'>Over there</span>",pt:"Lá"},{emoji:"🏔️",en:"Way <span class='hl-red'>over there</span>",pt:"Lá longe"},{emoji:"👆",en:"<span class='hl-red'>Over there</span>, see?",pt:"Lá, tá vendo?"},{emoji:"🚗",en:"Park <span class='hl-red'>over there</span>",pt:"Estaciona lá"}]},{type:"tip",cardClass:"purple",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>HERE</strong> = "RÍAR"<br><strong>THERE</strong> = "DÉRR"<br><strong>OVER THERE</strong> = "ÔUVER DÉRR"'},{type:"tip",cardClass:"cyan",icon:"💡",title:"THERE IS/ARE",text:"<strong>There is</strong> = Tem (singular)<br>There is a bank here.<br><br><strong>There are</strong> = Tem (plural)<br>There are two banks here."},{type:"comparison",cardClass:"red",title:"📏 NÍVEIS DE DISTÂNCIA",leftClass:"left-side",rightClass:"right-side",leftIcon:"📍",rightIcon:"🏔️",leftLabel:"PERTO",rightLabel:"LONGE",left:'<span class="hl-green">HERE</span> → <span class="hl-orange">THERE</span>',leftNote:"Aqui → Ali",right:'<span class="hl-red">OVER THERE</span>',rightNote:"Lá (distante)",explanation:"3 níveis: aqui, ali, lá"},{type:"quiz",cardClass:"cyan",question:"🎯 Para algo bem longe:",options:["here","there","over there"],correct:2},{type:"quiz",cardClass:"cyan",question:'🎯 "Vem aqui":',options:["Come there","Come here","Come over"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"The bathroom is right _____.",correctWord:"there"},{type:"list",cardClass:"gold",title:"📝 RESUMO - DISTÂNCIA",items:[{emoji:"📍",text:"<strong>HERE</strong> = aqui (perto)"},{emoji:"👉",text:"<strong>THERE</strong> = ali (médio)"},{emoji:"🏔️",text:"<strong>OVER THERE</strong> = lá (longe)"},{emoji:"✨",text:"<strong>RIGHT</strong> = bem (right here = bem aqui)"}]},{type:"end"}],vocabulary:[{emoji:"📍",pt:"Aqui",en:"Here"},{emoji:"👉",pt:"Ali",en:"There"},{emoji:"🏔️",pt:"Lá",en:"Over there"},{emoji:"📍",pt:"Bem aqui",en:"Right here"},{emoji:"👉",pt:"Bem ali",en:"Right there"},{emoji:"🏔️",pt:"Lá longe",en:"Way over there"},{emoji:"📍",pt:"Por aqui",en:"Around here"},{emoji:"👉",pt:"Por ali",en:"Around there"},{emoji:"❓",pt:"Onde? Aqui?",en:"Where? Here?"},{emoji:"👆",pt:"Não, lá",en:"No, over there"}]},{id:"here",title:"HERE",emoji:"📍✅",description:"Aqui (perto)",module:2,order:16,slides:[{type:"title",emoji:"📍✅",title:"HERE",subtitle:"Aqui (onde eu estou)"},{type:"situation",emoji:"📍",cardClass:"purple",text:'Você está em algum lugar.<br>Quer dizer: "Estou <strong>AQUI</strong>!"<br>Ou: "Vem <strong>AQUI</strong>!"'},{type:"sequence-step",stepNumber:1,totalSteps:5,emoji:"📱",english:"Hey, where are you? I'm here, in front of the store.",portuguese:"Ei, onde tá? Tô aqui, na frente da loja.",breakdown:"<strong>I'M HERE</strong> = estou aqui (onde eu estou agora). <strong>IN FRONT OF</strong> = na frente de."},{type:"sequence-step",stepNumber:2,totalSteps:5,emoji:"🚗",english:"I don't see you. Come here — I'm at the corner, by the red sign.",portuguese:"Não tô te vendo. Vem aqui — tô na esquina, perto da placa vermelha.",breakdown:"<strong>COME HERE</strong> = vem pra onde eu estou. HERE puxa a pessoa pro SEU lugar."},{type:"sequence-step",stepNumber:3,totalSteps:5,emoji:"✅",english:"OK, I'm here now. Get in! Sorry I'm late.",portuguese:"Tô aqui agora. Entra! Desculpa o atraso.",breakdown:"<strong>I'M HERE NOW</strong> = cheguei (agora estou aqui). <strong>GET IN</strong> = entra (no carro)."},{type:"sequence-step",stepNumber:4,totalSteps:5,emoji:"📦",english:"Put the boxes here, next to the wall. Right here, yes.",portuguese:"Coloca as caixas aqui, do lado da parede. Bem aqui, isso.",breakdown:"<strong>HERE</strong> = aqui (indicando o lugar). <strong>RIGHT HERE</strong> = bem aqui (mais específico, apontando)."},{type:"sequence-step",stepNumber:5,totalSteps:5,emoji:"📋",english:"Sign here, please. And write your phone number here.",portuguese:"Assina aqui, por favor. E escreve seu telefone aqui.",breakdown:"HERE em documentos: <strong>SIGN HERE</strong> = assine aqui. Você vai ouvir isso em banco, correio, hospital..."},{type:"rule",cardClass:"green",text:"Para indicar um lugar <strong>PERTO</strong> de você:",keyword:"HERE",keywordAfter:"Aqui (onde eu estou)"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>HERE</strong> soa como "RÍAR"<br><br>O H é aspirado, como um suspiro leve.'},{type:"example",cardClass:"green",emoji:"📍",question:"It's <span class='hl-green'>here</span>.",questionTr:"Está aqui.",answer:"(localização)",answerTr:"Perto de mim"},{type:"example",cardClass:"green",emoji:"👋",question:"Come <span class='hl-green'>here</span>.",questionTr:"Vem aqui.",answer:"(comando)",answerTr:"Para onde estou"},{type:"example",cardClass:"green",emoji:"🏠",question:"I live <span class='hl-green'>here</span>.",questionTr:"Eu moro aqui.",answer:"(lugar)",answerTr:"Neste lugar"},{type:"examples",cardClass:"green",title:"📍 HERE - USOS COMUNS",items:[{emoji:"🪑",en:"Sit <span class='hl-green'>here</span>.",pt:"Senta aqui."},{emoji:"📝",en:"Sign <span class='hl-green'>here</span>.",pt:"Assina aqui."},{emoji:"⏳",en:"Wait <span class='hl-green'>here</span>.",pt:"Espera aqui."},{emoji:"📦",en:"Put it <span class='hl-green'>here</span>.",pt:"Coloca aqui."}]},{type:"tip",cardClass:"gold",icon:"💡",title:"EXPRESSÕES ÚTEIS",text:"<strong>Here you go!</strong> = Aqui está!<br><strong>Here it is!</strong> = Achei! / Aqui está!<br><strong>Over here!</strong> = Aqui! (chamando atenção)"},{type:"comparison",cardClass:"cyan",title:"📍 HERE vs THERE ➡️",leftClass:"left-side",rightClass:"right-side",leftIcon:"📍",rightIcon:"➡️",leftLabel:"HERE (perto)",rightLabel:"THERE (longe)",left:"It's <span class='hl-green'>here</span>.",leftNote:"Perto de mim",right:"It's <span class='hl-orange'>there</span>.",rightNote:"Longe de mim",explanation:"Onde EU estou = <strong>HERE</strong> | Longe de mim = <strong>THERE</strong>"},{type:"comparison",cardClass:"red",title:"⚠️ CUIDADO",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"Come to here.",leftNote:"Não precisa de TO",right:"Come here.",rightNote:"HERE já é completo",explanation:"<strong>HERE</strong> não precisa de preposição!"},{type:"quiz",cardClass:"cyan",question:'🎯 "Aqui" em inglês:',options:["There","Here","Where"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Vem aqui" em inglês:',options:["Come to here","Come here","Go here"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"I work _____. (neste lugar)",correctWord:"here"},{type:"list",cardClass:"gold",title:"📝 RESUMO - HERE",items:[{emoji:"📍",text:"<strong>HERE</strong> = aqui"},{emoji:"✅",text:"Lugar PERTO de quem fala"},{emoji:"⭐",text:"Here you go! = Aqui está!"},{emoji:"⚠️",text:'Sem preposição: Come here (não "to here")'}]},{type:"end"}],vocabulary:[{emoji:"📍",pt:"Está aqui",en:"It's here"},{emoji:"👋",pt:"Vem aqui",en:"Come here"},{emoji:"🪑",pt:"Senta aqui",en:"Sit here"},{emoji:"📝",pt:"Assina aqui",en:"Sign here"},{emoji:"🏠",pt:"Eu moro aqui",en:"I live here"},{emoji:"💼",pt:"Eu trabalho aqui",en:"I work here"},{emoji:"⏳",pt:"Espera aqui",en:"Wait here"},{emoji:"👀",pt:"Olha aqui",en:"Look here"},{emoji:"📦",pt:"Coloca aqui",en:"Put it here"},{emoji:"✋",pt:"Para aqui",en:"Stop here"}]},{id:"there",title:"THERE",emoji:"📍➡️",description:"Ali/Lá (longe)",module:2,order:17,slides:[{type:"title",emoji:"📍➡️",title:"THERE",subtitle:"Ali/Lá (longe de mim)"},{type:"situation",emoji:"👉",cardClass:"purple",text:'Você aponta para um lugar distante:<br>"Está <strong>LÁ</strong>!"<br>Ou: "Vai <strong>LÁ</strong>!"'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🗺️",english:"Excuse me, is there a pharmacy near here?",portuguese:"Com licença, tem farmácia perto daqui?",breakdown:"<strong>IS THERE</strong> = tem/existe? Pergunta pra achar lugares."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"👉",english:"Yes! It's right there, across the street.",portuguese:"Sim! Tá bem ali, do outro lado da rua.",breakdown:"<strong>RIGHT THERE</strong> = bem ali. ACROSS THE STREET = outro lado."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"🏥",english:"And a hospital? There's one on Main Street.",portuguese:"E hospital? Tem um na Main Street.",breakdown:"<strong>THERE'S ONE</strong> = tem um. THERE'S = there is."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"🙏",english:"Thank you! I'll go there now.",portuguese:"Obrigado! Vou lá agora.",breakdown:"<strong>GO THERE</strong> = ir lá. THERE = naquele lugar."},{type:"rule",cardClass:"orange",text:"Para indicar um lugar <strong>LONGE</strong> de você:",keyword:"THERE",keywordAfter:"Ali/Lá (longe de mim)"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>THERE</strong> soa como "DÉR"<br><br>⚠️ Não confundir com THEIR (deles) - mesma pronúncia!'},{type:"example",cardClass:"orange",emoji:"📍",question:"It's <span class='hl-orange'>there</span>.",questionTr:"Está ali/lá.",answer:"(localização)",answerTr:"Longe de mim"},{type:"example",cardClass:"orange",emoji:"🚶",question:"Go <span class='hl-orange'>there</span>.",questionTr:"Vai lá.",answer:"(comando)",answerTr:"Para longe"},{type:"example",cardClass:"orange",emoji:"🏠",question:"He lives <span class='hl-orange'>there</span>.",questionTr:"Ele mora lá.",answer:"(lugar)",answerTr:"Naquele lugar"},{type:"examples",cardClass:"orange",title:"➡️ THERE - USOS COMUNS",items:[{emoji:"👀",en:"Look <span class='hl-orange'>there</span>!",pt:"Olha ali!"},{emoji:"⏳",en:"Wait <span class='hl-orange'>there</span>.",pt:"Espera lá."},{emoji:"🪑",en:"Sit <span class='hl-orange'>there</span>.",pt:"Senta lá."},{emoji:"📦",en:"Put it <span class='hl-orange'>there</span>.",pt:"Coloca ali."}]},{type:"tip",cardClass:"gold",icon:"💡",title:"OVER THERE",text:'<strong>Over there</strong> = ali/lá (mais enfático)<br><br>"The bathroom is over there."<br>O banheiro é ali.'},{type:"comparison",cardClass:"cyan",title:"📍 HERE vs THERE ➡️",leftClass:"left-side",rightClass:"right-side",leftIcon:"📍",rightIcon:"➡️",leftLabel:"HERE (perto)",rightLabel:"THERE (longe)",left:"Come <span class='hl-green'>here</span>!",leftNote:"Vem para onde EU estou",right:"Go <span class='hl-orange'>there</span>!",rightNote:"Vai para onde EU NÃO estou",explanation:"COME here (vem) | GO there (vai)"},{type:"tip",cardClass:"green",icon:"⚠️",title:"THERE vs THERE IS/ARE",text:"<strong>THERE</strong> (lugar) ≠ <strong>THERE IS/ARE</strong> (existe)<br><br>Put it <strong>there</strong>. = Coloca ali.<br><strong>There is</strong> a book. = Tem um livro."},{type:"comparison",cardClass:"red",title:"⚠️ CUIDADO",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"Go to there.",leftNote:"Não precisa de TO",right:"Go there.",rightNote:"THERE já é completo",explanation:"<strong>THERE</strong> não precisa de preposição!"},{type:"quiz",cardClass:"cyan",question:'🎯 "Ali/Lá" em inglês:',options:["Here","There","Where"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Vai lá" em inglês:',options:["Go to there","Go there","Come there"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"She works _____. (naquele lugar)",correctWord:"there"},{type:"list",cardClass:"gold",title:"📝 RESUMO - THERE",items:[{emoji:"➡️",text:"<strong>THERE</strong> = ali/lá"},{emoji:"📍",text:"Lugar LONGE de quem fala"},{emoji:"⭐",text:"Over there = ali (enfático)"},{emoji:"⚠️",text:'Sem preposição: Go there (não "to there")'}]},{type:"end"}],vocabulary:[{emoji:"📍",pt:"Está ali",en:"It's there"},{emoji:"🚶",pt:"Vai lá",en:"Go there"},{emoji:"👀",pt:"Olha ali",en:"Look there"},{emoji:"🏢",pt:"É ali",en:"It's over there"},{emoji:"⏳",pt:"Espera lá",en:"Wait there"},{emoji:"🪑",pt:"Senta lá",en:"Sit there"},{emoji:"📦",pt:"Coloca ali",en:"Put it there"},{emoji:"✋",pt:"Para ali",en:"Stop there"},{emoji:"🏠",pt:"Ele mora lá",en:"He lives there"},{emoji:"💼",pt:"Ela trabalha lá",en:"She works there"}]},{id:"do-affirmative",title:"DO (Affirmative)",emoji:"✅📝",description:"Fazer (afirmação)",module:2,order:18,slides:[{type:"title",emoji:"✅📝",title:"DO",subtitle:"Fazer (verbo e auxiliar)"},{type:"situation",emoji:"🍔",cardClass:"cyan",text:'Horário de almoço. Seu colega americano pergunta: "What do you DO every day?" Você quer contar sua rotina — acordar, pegar ônibus, trabalhar, buscar o filho, estudar inglês, dormir.<br><br>Em inglês, quando fala de ROTINA (coisas que faz sempre), usa o verbo no presente simples: "I work. I cook. I study." DO é o verbo mais básico — FAZER — e aparece em toda conversa sobre o dia a dia.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"💬",english:"So what do you do every day? I wake up at 5 and take the bus.",portuguese:"E o que você faz todo dia? Acordo às 5 e pego o ônibus.",breakdown:"<strong>WHAT DO YOU DO</strong> = o que você faz? Pergunta clássica sobre rotina. Resposta: verbo simples."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"🏗️",english:"I work from 7 to 4. Then I pick up my kid from school.",portuguese:"Trabalho das 7 às 4. Depois busco meu filho na escola.",breakdown:"<strong>I WORK</strong> = eu trabalho. <strong>I PICK UP</strong> = eu busco. Presente simples pra rotina."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"📚",english:"At night I cook dinner and study English. I sleep at 11.",portuguese:"À noite faço jantar e estudo inglês. Durmo às 11.",breakdown:"<strong>I COOK</strong>, <strong>I STUDY</strong>, <strong>I SLEEP</strong> — tudo presente simples. Sem -ING pra rotina!"},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"💪",english:"Wow, you do a lot! Yes, I do. But I like it.",portuguese:"Caramba, faz muita coisa! É verdade. Mas eu gosto.",breakdown:'<strong>I DO</strong> = eu faço/sim (enfático). "Yes, I do" = forma forte de confirmar. Muito natural!'},{type:"rule",cardClass:"cyan",text:'<strong>DO</strong> é o verbo "FAZER":',keyword:"DO",keywordAfter:"Fazer (ação)"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>DO</strong> soa como "DU"<br><strong>DOES</strong> soa como "DÁZ"<br>(he/she/it = DOES)'},{type:"example",cardClass:"cyan",emoji:"📝",question:'I <span class="hl-cyan">do</span> my homework.',questionTr:"Eu faço meu dever.",answer:"(fazer)",answerTr:"Ação"},{type:"example",cardClass:"cyan",emoji:"💪",question:'I <span class="hl-cyan">do</span> my best.',questionTr:"Eu faço o meu melhor.",answer:"(expressão)",answerTr:"Muito comum!"},{type:"example",cardClass:"cyan",emoji:"🏋️",question:'I <span class="hl-cyan">do</span> exercise every day.',questionTr:"Eu faço exercício todo dia.",answer:"(fazer)",answerTr:"Rotina"},{type:"examples",cardClass:"cyan",title:"✅ DO - EXPRESSÕES COMUNS",items:[{emoji:"🍽️",en:'I <span class="hl-cyan">do</span> the dishes.',pt:"Eu lavo a louça."},{emoji:"👕",en:'I <span class="hl-cyan">do</span> the laundry.',pt:"Eu lavo a roupa."},{emoji:"🧹",en:'I <span class="hl-cyan">do</span> the cleaning.',pt:"Eu faço a limpeza."},{emoji:"💼",en:'I <span class="hl-cyan">do</span> business.',pt:"Eu faço negócios."}]},{type:"tip",cardClass:"green",icon:"💡",title:"DO vs DOES",text:"<strong>I/YOU/WE/THEY</strong> → DO<br><strong>HE/SHE/IT</strong> → DOES<br><br>She <strong>does</strong> the dishes.<br>He <strong>does</strong> his homework."},{type:"comparison",cardClass:"cyan",title:"🛠️ DO vs MAKE",leftClass:"left-side",rightClass:"right-side",leftIcon:"📋",rightIcon:"🔨",leftLabel:"DO (atividades)",rightLabel:"MAKE (criar algo)",left:'I <span class="hl-cyan">do</span> homework.',leftNote:"Atividades, tarefas",right:'I <span class="hl-purple">make</span> coffee.',rightNote:"Criar, produzir",explanation:"DO = atividades | MAKE = criar algo físico"},{type:"tip",cardClass:"gold",icon:"⭐",title:"PERGUNTA ESSENCIAL",text:`<strong>"What do you do?"</strong><br>O que você faz? (profissão)<br><br>Resposta: I'm a teacher. / I work at...`},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"He do his homework.",leftNote:"HE precisa de DOES",right:"He does his homework.",rightNote:"DOES para he/she/it",explanation:"Com HE/SHE/IT: sempre <strong>DOES</strong>"},{type:"quiz",cardClass:"cyan",question:'🎯 "O que você faz?" (profissão):',options:["What you do?","What do you do?","What are you do?"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Ela faz a limpeza":',options:["She do the cleaning","She does the cleaning","She doing the cleaning"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete (ele faz):",sentence:"He _____ his homework every day.",correctWord:"does"},{type:"list",cardClass:"gold",title:"📝 RESUMO - DO",items:[{emoji:"✅",text:"<strong>DO</strong> = fazer"},{emoji:"👤",text:"I/you/we/they DO"},{emoji:"👨",text:"He/she/it DOES"},{emoji:"💼",text:'"What do you do?" = profissão'}]},{type:"end"}],vocabulary:[{emoji:"📝",pt:"Eu faço meu dever",en:"I do my homework"},{emoji:"💪",pt:"Eu faço o meu melhor",en:"I do my best"},{emoji:"💼",pt:"O que você faz?",en:"What do you do?"},{emoji:"🧹",pt:"Eu faço a limpeza",en:"I do the cleaning"},{emoji:"🍽️",pt:"Eu lavo a louça",en:"I do the dishes"},{emoji:"👕",pt:"Eu lavo a roupa",en:"I do the laundry"},{emoji:"💼",pt:"Eu faço negócios",en:"I do business"},{emoji:"🏋️",pt:"Eu faço exercício",en:"I do exercise"},{emoji:"🎯",pt:"Faço isso todo dia",en:"I do this every day"},{emoji:"✅",pt:"Pronto!",en:"Done!"}]},{id:"do-questions",title:"DO (Questions)",emoji:"❓📝",description:"Perguntas com DO",module:2,order:19,slides:[{type:"title",emoji:"❓📝",title:"DO (Questions)",subtitle:"Fazer perguntas"},{type:"situation",emoji:"🏠",cardClass:"cyan",text:'Você acabou de se mudar e encontra o vizinho no corredor. Ele puxa conversa: "Do you live here? Do you have kids? Do you like BBQ?"<br><br>Pra fazer pergunta sobre hábitos, rotina e preferências, você precisa do DO na frente: "DO you work?" "DO you speak English?" Sem DO, soa como afirmação. Com DO, vira pergunta de verdade.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🏠",english:"Hey! Do you live in this building? Yes! I just moved in.",portuguese:"Ei! Mora nesse prédio? Sim! Acabei de me mudar.",breakdown:"<strong>DO YOU LIVE</strong> = você mora? DO na frente transforma em pergunta. JUST MOVED IN = acabei de mudar."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"👶",english:"Nice! Do you have kids? Yes, a boy. Do you?",portuguese:"Legal! Tem filhos? Sim, um menino. E você?",breakdown:"<strong>DO YOU HAVE</strong> = você tem? <strong>DO YOU?</strong> = e você? (devolvendo a pergunta, super natural)."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"🏗️",english:"Two girls! Do you work around here? Yes, construction.",portuguese:"Duas meninas! Trabalha aqui perto? Sim, construção.",breakdown:"<strong>DO YOU WORK</strong> = você trabalha? AROUND HERE = por aqui/perto daqui."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"🍖",english:"Cool. Do you guys like BBQ? We do it every Sunday!",portuguese:"Legal. Vocês gostam de churrasco? Fazemos todo domingo!",breakdown:"<strong>DO YOU GUYS LIKE</strong> = vocês gostam? YOU GUYS = vocês (informal). EVERY SUNDAY = todo domingo."},{type:"rule",cardClass:"cyan",text:"<strong>DO</strong> é usado para formar <strong>PERGUNTAS</strong>:",keyword:"DO + sujeito + verbo?",keywordAfter:"Do you like...? Do they know...?"},{type:"tip",cardClass:"orange",icon:"🔄",title:"ESTRUTURA DA PERGUNTA",text:"<strong>DO</strong> + sujeito + verbo + ...?<br><br>Do you <strong>like</strong> coffee?<br>Do they <strong>know</strong> him?"},{type:"example",cardClass:"cyan",emoji:"☕",question:'<span class="hl-cyan">Do</span> you like coffee?',questionTr:"Você gosta de café?",answer:"Yes, I do. / No, I don't.",answerTr:"Respostas"},{type:"example",cardClass:"cyan",emoji:"🏠",question:'<span class="hl-cyan">Do</span> you live here?',questionTr:"Você mora aqui?",answer:"Yes, I do.",answerTr:"Resposta curta"},{type:"example",cardClass:"cyan",emoji:"🗣️",question:'<span class="hl-cyan">Do</span> you speak English?',questionTr:"Você fala inglês?",answer:"Yes, I do.",answerTr:"Resposta curta"},{type:"examples",cardClass:"cyan",title:"❓ PERGUNTAS ESSENCIAIS",items:[{emoji:"💼",en:'<span class="hl-cyan">Do</span> you work here?',pt:"Você trabalha aqui?"},{emoji:"🚗",en:'<span class="hl-cyan">Do</span> you have a car?',pt:"Você tem carro?"},{emoji:"🤔",en:'<span class="hl-cyan">Do</span> you understand?',pt:"Você entende?"},{emoji:"💭",en:'<span class="hl-cyan">Do</span> you want to go?',pt:"Você quer ir?"}]},{type:"tip",cardClass:"green",icon:"💡",title:"RESPOSTAS CURTAS",text:"<strong>Yes, I do.</strong> = Sim.<br><strong>No, I don't.</strong> = Não.<br><br>Resposta curta é mais natural!"},{type:"comparison",cardClass:"cyan",title:"❓ DO vs DOES",leftClass:"left-side",rightClass:"right-side",leftIcon:"👥",rightIcon:"👤",leftLabel:"DO (I/you/we/they)",rightLabel:"DOES (he/she/it)",left:'<span class="hl-cyan">Do</span> you like coffee?',leftNote:"Para YOU",right:'<span class="hl-purple">Does</span> she like coffee?',rightNote:"Para SHE",explanation:"DO = I/you/we/they | DOES = he/she/it"},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"You like coffee?",leftNote:"Faltou o DO",right:"Do you like coffee?",rightNote:"Com DO = pergunta",explanation:"Perguntas precisam de <strong>DO</strong> no início!"},{type:"quiz",cardClass:"cyan",question:'🎯 "Você fala inglês?" em inglês:',options:["You speak English?","Do you speak English?","Are you speak English?"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 Resposta curta para "Do you like pizza?":',options:["Yes, I like","Yes, I do","Yes, do I"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete a pergunta:",sentence:"_____ you have time?",correctWord:"Do"},{type:"list",cardClass:"gold",title:"📝 RESUMO - DO (Perguntas)",items:[{emoji:"❓",text:"Estrutura: DO + sujeito + verbo?"},{emoji:"👥",text:"DO para I/you/we/they"},{emoji:"👤",text:"DOES para he/she/it"},{emoji:"✅",text:"Respostas: Yes, I do / No, I don't"}]},{type:"end"}],vocabulary:[{emoji:"☕",pt:"Você gosta de café?",en:"Do you like coffee?"},{emoji:"🏠",pt:"Você mora aqui?",en:"Do you live here?"},{emoji:"🗣️",pt:"Você fala inglês?",en:"Do you speak English?"},{emoji:"💼",pt:"Você trabalha aqui?",en:"Do you work here?"},{emoji:"🚗",pt:"Você tem carro?",en:"Do you have a car?"},{emoji:"🤔",pt:"Você entende?",en:"Do you understand?"},{emoji:"💭",pt:"Você quer ir?",en:"Do you want to go?"},{emoji:"⏰",pt:"Você tem tempo?",en:"Do you have time?"},{emoji:"💡",pt:"Você precisa de ajuda?",en:"Do you need help?"},{emoji:"🎵",pt:"Você gosta de música?",en:"Do you like music?"}]},{id:"do-negative",title:"DO (Negative)",emoji:"❌📝",description:"Negação com DO",module:2,order:20,slides:[{type:"title",emoji:"❌📝",title:"DON'T / DOESN'T",subtitle:"Negar com DO"},{type:"situation",emoji:"🎉",cardClass:"cyan",text:`Você foi no churrasco do vizinho. Ele oferece cerveja: "Want a beer?" Você não bebe: "I DON'T drink." Oferece pork ribs: "I DON'T eat pork."<br><br>DON'T é a palavra mais poderosa pra dizer NÃO em inglês. Em português é só "não" antes do verbo. Em inglês, DON'T vai entre o sujeito e o verbo: "I DON'T understand." Sem DON'T, não tem negação.`},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🍺",english:"Want a beer? No thanks, I don't drink. Just water, please.",portuguese:"Quer cerveja? Não obrigado, não bebo. Só água, por favor.",breakdown:"<strong>I DON'T DRINK</strong> = eu não bebo. DON'T + verbo = negação. Educado e direto."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"🥩",english:"Try this! I don't eat pork, but I eat everything else.",portuguese:"Experimenta! Não como porco, mas como todo o resto.",breakdown:"<strong>I DON'T EAT</strong> = eu não como. BUT = mas. EVERYTHING ELSE = todo o resto."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"🏈",english:"Do you watch football? I don't understand the rules yet!",portuguese:"Assiste futebol americano? Ainda não entendo as regras!",breakdown:"<strong>I DON'T UNDERSTAND</strong> = não entendo. YET = ainda. Frase honesta e simpática!"},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"😂",english:"Don't worry! We don't understand them either. Haha!",portuguese:"Relaxa! A gente também não entende. Haha!",breakdown:"<strong>DON'T WORRY</strong> = não se preocupe. <strong>EITHER</strong> = também (na negativa). Humor quebra o gelo!"},{type:"rule",cardClass:"red",text:"<strong>DON'T</strong> (do not) serve para <strong>NEGAR</strong>:",keyword:"DON'T + verbo",keywordAfter:"Não faço / Não gosto / Não sei"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:`<strong>DON'T</strong> soa como "DÔUNT"<br><strong>DOESN'T</strong> soa como "DÁZNT"<br>(he/she/it = DOESN'T)`},{type:"example",cardClass:"red",emoji:"☕",question:"I <span class='hl-red'>don't</span> like coffee.",questionTr:"Eu não gosto de café.",answer:"(negação)",answerTr:"DON'T para I/you/we/they"},{type:"example",cardClass:"red",emoji:"🤷",question:"I <span class='hl-red'>don't</span> know.",questionTr:"Eu não sei.",answer:"(muito comum!)",answerTr:"Frase essencial"},{type:"example",cardClass:"red",emoji:"🤔",question:"I <span class='hl-red'>don't</span> understand.",questionTr:"Eu não entendo.",answer:"(muito comum!)",answerTr:"Frase essencial"},{type:"examples",cardClass:"red",title:"❌ NEGAÇÕES COMUNS",items:[{emoji:"💭",en:"I <span class='hl-red'>don't</span> want.",pt:"Eu não quero."},{emoji:"💡",en:"I <span class='hl-red'>don't</span> need.",pt:"Eu não preciso."},{emoji:"🗣️",en:"I <span class='hl-red'>don't</span> speak Spanish.",pt:"Eu não falo espanhol."},{emoji:"🍖",en:"I <span class='hl-red'>don't</span> eat meat.",pt:"Eu não como carne."}]},{type:"tip",cardClass:"green",icon:"💡",title:"DON'T vs DOESN'T",text:"<strong>I/YOU/WE/THEY</strong> → DON'T<br><strong>HE/SHE/IT</strong> → DOESN'T<br><br>She <strong>doesn't</strong> like coffee.<br>He <strong>doesn't</strong> know."},{type:"examples",cardClass:"purple",title:"❌ DOESN'T (he/she/it)",items:[{emoji:"☕",en:"She <span class='hl-purple'>doesn't</span> like coffee.",pt:"Ela não gosta de café."},{emoji:"💼",en:"He <span class='hl-purple'>doesn't</span> work here.",pt:"Ele não trabalha aqui."},{emoji:"⏰",en:"It <span class='hl-purple'>doesn't</span> work.",pt:"Não funciona."}]},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"I no understand.",leftNote:"Português direto",right:"I don't understand.",rightNote:"Use DON'T",explanation:`Em inglês: <strong>DON'T</strong> + verbo (não "no")`},{type:"comparison",cardClass:"red",title:"⚠️ OUTRO ERRO",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"She don't like.",leftNote:"DON'T com SHE",right:"She doesn't like.",rightNote:"DOESN'T para she",explanation:"Com HE/SHE/IT: sempre <strong>DOESN'T</strong>"},{type:"quiz",cardClass:"cyan",question:'🎯 "Eu não entendo" em inglês:',options:["I no understand","I don't understand","I not understand"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Ela não trabalha aqui":',options:["She don't work here","She doesn't work here","She no work here"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete (ele não sabe):",sentence:"He _____ know.",correctWord:"doesn't"},{type:"list",cardClass:"gold",title:"📝 RESUMO - DON'T / DOESN'T",items:[{emoji:"👥",text:"<strong>DON'T</strong> para I/you/we/they"},{emoji:"👤",text:"<strong>DOESN'T</strong> para he/she/it"},{emoji:"🔤",text:"Estrutura: DON'T/DOESN'T + verbo"},{emoji:"⭐",text:"Essenciais: I don't know / I don't understand"}]},{type:"end"}],vocabulary:[{emoji:"☕",pt:"Não gosto de café",en:"I don't like coffee"},{emoji:"🤷",pt:"Eu não sei",en:"I don't know"},{emoji:"🤔",pt:"Eu não entendo",en:"I don't understand"},{emoji:"💭",pt:"Eu não quero",en:"I don't want"},{emoji:"💡",pt:"Eu não preciso",en:"I don't need"},{emoji:"🗣️",pt:"Eu não falo espanhol",en:"I don't speak Spanish"},{emoji:"🚗",pt:"Eu não dirijo",en:"I don't drive"},{emoji:"🍖",pt:"Eu não como carne",en:"I don't eat meat"},{emoji:"💰",pt:"Eu não tenho dinheiro",en:"I don't have money"},{emoji:"⏰",pt:"Eu não tenho tempo",en:"I don't have time"}]},{id:"does",title:"DOES",emoji:"👤📝",description:"Terceira pessoa (he/she/it)",module:2,order:21,slides:[{type:"title",emoji:"👤📝",title:"DOES",subtitle:"Para he/she/it"},{type:"situation",emoji:"📱",cardClass:"cyan",text:`Você liga pro amigo no Brasil e conta sobre seu roommate americano. "DOES he cook? No, he DOESN'T cook." "DOES he speak Portuguese? A little!"<br><br>Quando fala de HE, SHE ou IT, o DO vira DOES. É a mesma lógica do "S" no verbo (he workS, she cookS) — mas na pergunta e na negativa, usa DOES e o verbo volta ao normal. He/she/it = DOES. O resto = DO.`},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🏠",english:"My roommate is cool. He works at night. He doesn't make noise.",portuguese:"Meu colega de quarto é legal. Trabalha à noite. Não faz barulho.",breakdown:"<strong>HE DOESN'T</strong> = ele não. DOESN'T (não DOESN'T) pra HE/SHE/IT. O verbo volta ao normal: make (não makes)."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"🍳",english:"Does he cook? No, he doesn't. He eats out every day.",portuguese:"Ele cozinha? Não. Come fora todo dia.",breakdown:"<strong>DOES HE COOK</strong> = ele cozinha? DOES na frente pra HE/SHE/IT. EATS OUT = come fora."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"🇧🇷",english:"Does he speak Portuguese? A little! His girlfriend is Brazilian.",portuguese:"Fala português? Um pouco! A namorada é brasileira.",breakdown:"<strong>DOES HE SPEAK</strong> = ele fala? A LITTLE = um pouco. Resposta curta e natural."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"💰",english:"Does he pay rent on time? Always! He's very responsible.",portuguese:"Paga aluguel em dia? Sempre! É muito responsável.",breakdown:"<strong>DOES HE PAY</strong> = ele paga? ON TIME = em dia/no prazo. RESPONSIBLE = responsável."},{type:"rule",cardClass:"cyan",text:"Para <strong>HE/SHE/IT</strong> use <strong>DOES</strong>:",keyword:"DOES",keywordAfter:"Does he...? / She doesn't..."},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:`<strong>DOES</strong> soa como "DÁZ"<br><strong>DOESN'T</strong> soa como "DÁZNT"`},{type:"example",cardClass:"cyan",emoji:"☕",question:'<span class="hl-cyan">Does</span> he like coffee?',questionTr:"Ele gosta de café?",answer:"Yes, he does.",answerTr:"Resposta curta"},{type:"example",cardClass:"cyan",emoji:"🏠",question:'<span class="hl-cyan">Does</span> she live here?',questionTr:"Ela mora aqui?",answer:"No, she doesn't.",answerTr:"Resposta curta"},{type:"example",cardClass:"cyan",emoji:"⏰",question:'<span class="hl-cyan">Does</span> it work?',questionTr:"Funciona?",answer:"Yes, it does.",answerTr:"Para coisas também!"},{type:"examples",cardClass:"cyan",title:"❓ PERGUNTAS COM DOES",items:[{emoji:"💼",en:'<span class="hl-cyan">Does</span> she work?',pt:"Ela trabalha?"},{emoji:"🚗",en:'<span class="hl-cyan">Does</span> he have a car?',pt:"Ele tem carro?"},{emoji:"🤔",en:'<span class="hl-cyan">Does</span> she understand?',pt:"Ela entende?"},{emoji:"🌧️",en:'<span class="hl-cyan">Does</span> it rain a lot?',pt:"Chove muito?"}]},{type:"examples",cardClass:"red",title:"❌ NEGAÇÃO COM DOESN'T",items:[{emoji:"🗣️",en:"She <span class='hl-red'>doesn't</span> speak English.",pt:"Ela não fala inglês."},{emoji:"💼",en:"He <span class='hl-red'>doesn't</span> work here.",pt:"Ele não trabalha aqui."},{emoji:"❌",en:"It <span class='hl-red'>doesn't</span> matter.",pt:"Não importa."}]},{type:"tip",cardClass:"gold",icon:"⚠️",title:"REGRA IMPORTANTE",text:"Com DOES, o verbo fica <strong>SEM S</strong>!<br><br>❌ Does she <strong>likes</strong>?<br>✅ Does she <strong>like</strong>?<br><br>O S vai pro DOES, não pro verbo!"},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"Does she likes coffee?",leftNote:"S duplicado",right:"Does she like coffee?",rightNote:"Verbo sem S",explanation:"Com DOES, verbo fica na forma base (sem S)!"},{type:"quiz",cardClass:"cyan",question:'🎯 "Ela mora aqui?" em inglês:',options:["Do she live here?","Does she live here?","Does she lives here?"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Ele não sabe":',options:["He don't know","He doesn't know","He doesn't knows"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"_____ she speak English?",correctWord:"Does"},{type:"list",cardClass:"gold",title:"📝 RESUMO - DOES",items:[{emoji:"👤",text:"<strong>DOES</strong> para he/she/it"},{emoji:"❓",text:"Pergunta: Does she like...?"},{emoji:"❌",text:"Negação: She doesn't like..."},{emoji:"⚠️",text:"Verbo SEM S: Does she like (não likes)"}]},{type:"end"}],vocabulary:[{emoji:"☕",pt:"Ele gosta de café?",en:"Does he like coffee?"},{emoji:"🗣️",pt:"Ela não fala inglês",en:"She doesn't speak English"},{emoji:"🏠",pt:"Ele mora aqui?",en:"Does he live here?"},{emoji:"💼",pt:"Ela trabalha?",en:"Does she work?"},{emoji:"🚗",pt:"Ele tem carro?",en:"Does he have a car?"},{emoji:"🤔",pt:"Ela entende?",en:"Does she understand?"},{emoji:"⏰",pt:"Isso funciona?",en:"Does it work?"},{emoji:"🌧️",pt:"Chove muito aqui?",en:"Does it rain a lot here?"},{emoji:"💡",pt:"Ele sabe?",en:"Does he know?"},{emoji:"❌",pt:"Isso não importa",en:"It doesn't matter"}]},{id:"has",title:"HAS",emoji:"👤📦",description:"Ter (he/she/it)",module:2,order:22,slides:[{type:"title",emoji:"👤📦",title:"HAS",subtitle:"Ter (para he/she/it)"},{type:"situation",emoji:"📱",cardClass:"cyan",text:'Videochamada com a família no Brasil. Você mostra fotos: "My boss HAS a huge truck! My apartment HAS two bedrooms. Lucas HAS so many friends now!"<br><br>HAVE vira HAS quando fala de HE, SHE ou IT. É a mesma regra do -S nos verbos. "I HAVE a car" → "He HAS a car." Simples, mas brasileiro erra muito porque em português não tem essa troca.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🚛",english:"Look, my boss has a huge truck! He has three dogs too.",portuguese:"Olha, meu chefe tem um caminhão enorme! Tem três cachorros também.",breakdown:"<strong>HAS</strong> = tem (HE/SHE/IT). I HAVE → He HAS. A HUGE truck = um caminhão ENORME."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"🏠",english:"My apartment has two bedrooms. It has a nice view.",portuguese:"Meu apartamento tem dois quartos. Tem uma vista bonita.",breakdown:"<strong>IT HAS</strong> = (ele/isso) tem. Apartamento = IT. A NICE VIEW = uma vista bonita."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"👦",english:"Lucas has a lot of friends now! He has good grades too.",portuguese:"O Lucas tem muitos amigos agora! Boas notas também.",breakdown:"<strong>HAS A LOT OF</strong> = tem muitos/muitas. GOOD GRADES = boas notas."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"💼",english:"She has a new job! Life here has its challenges, but we're OK.",portuguese:"Ela tem emprego novo! A vida aqui tem seus desafios, mas tamos bem.",breakdown:"<strong>SHE HAS</strong> = ela tem. <strong>LIFE HAS</strong> = a vida tem. ITS challenges = seus desafios (IT → ITS)."},{type:"rule",cardClass:"cyan",text:"<strong>HAS</strong> = ter (para <strong>HE/SHE/IT</strong>):",keyword:"HAS",keywordAfter:"Ele tem / Ela tem / Isso tem"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>HAS</strong> soa como "RÉZ"<br><br>Parece com "has" em português (como em "gás").'},{type:"example",cardClass:"cyan",emoji:"🚗",question:'He <span class="hl-cyan">has</span> a car.',questionTr:"Ele tem um carro.",answer:"(he = HAS)",answerTr:"Terceira pessoa"},{type:"example",cardClass:"cyan",emoji:"👶",question:'She <span class="hl-cyan">has</span> two kids.',questionTr:"Ela tem dois filhos.",answer:"(she = HAS)",answerTr:"Terceira pessoa"},{type:"example",cardClass:"cyan",emoji:"🔋",question:'It <span class="hl-cyan">has</span> battery.',questionTr:"Tem bateria.",answer:"(it = HAS)",answerTr:"Para coisas também!"},{type:"examples",cardClass:"cyan",title:"👤 HAS - EXEMPLOS",items:[{emoji:"🐕",en:'She <span class="hl-cyan">has</span> a dog.',pt:"Ela tem um cachorro."},{emoji:"💼",en:'He <span class="hl-cyan">has</span> a good job.',pt:"Ele tem um bom emprego."},{emoji:"🏠",en:'She <span class="hl-cyan">has</span> a big house.',pt:"Ela tem uma casa grande."},{emoji:"💡",en:'She <span class="hl-cyan">has</span> an idea.',pt:"Ela tem uma ideia."}]},{type:"comparison",cardClass:"cyan",title:"👥 HAVE vs HAS 👤",leftClass:"left-side",rightClass:"right-side",leftIcon:"👥",rightIcon:"👤",leftLabel:"HAVE (I/you/we/they)",rightLabel:"HAS (he/she/it)",left:'I <span class="hl-cyan">have</span> a car.',leftNote:"Para EU",right:'He <span class="hl-purple">has</span> a car.',rightNote:"Para ELE",explanation:"Mesma regra: 3ª pessoa muda!"},{type:"tip",cardClass:"green",icon:"💡",title:"HAS PARA DOENÇAS/CONDIÇÕES",text:'<strong>He has a cold.</strong> = Ele está gripado.<br><strong>She has a headache.</strong> = Ela está com dor de cabeça.<br><br>Em inglês, você "tem" doenças!'},{type:"examples",cardClass:"purple",title:"🤒 HAS + CONDIÇÕES",items:[{emoji:"😷",en:'He <span class="hl-cyan">has</span> a cold.',pt:"Ele está gripado."},{emoji:"🤕",en:'She <span class="hl-cyan">has</span> a headache.',pt:"Ela está com dor de cabeça."},{emoji:"🤒",en:'He <span class="hl-cyan">has</span> a fever.',pt:"Ele está com febre."}]},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"She have a car.",leftNote:"HAVE com SHE",right:"She has a car.",rightNote:"HAS para she",explanation:"Com HE/SHE/IT: sempre <strong>HAS</strong>"},{type:"quiz",cardClass:"cyan",question:'🎯 "Ela tem tempo" em inglês:',options:["She have time","She has time","She haves time"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Ele está gripado":',options:["He is cold","He has a cold","He have a cold"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"She _____ a big family.",correctWord:"has"},{type:"list",cardClass:"gold",title:"📝 RESUMO - HAS",items:[{emoji:"👤",text:"<strong>HAS</strong> = tem (he/she/it)"},{emoji:"🔄",text:"I/you/we/they HAVE → he/she/it HAS"},{emoji:"🤒",text:"He has a cold = Está gripado"},{emoji:"⚠️",text:'Nunca "haves" ou "have" com he/she'}]},{type:"end"}],vocabulary:[{emoji:"🚗",pt:"Ele tem um carro",en:"He has a car"},{emoji:"👶",pt:"Ela tem dois filhos",en:"She has two kids"},{emoji:"🐕",pt:"Ela tem um cachorro",en:"She has a dog"},{emoji:"💼",pt:"Ele tem um bom trabalho",en:"He has a good job"},{emoji:"🏠",pt:"Ela tem uma casa grande",en:"She has a big house"},{emoji:"⏰",pt:"Ele tem tempo",en:"He has time"},{emoji:"💰",pt:"Ela tem dinheiro",en:"She has money"},{emoji:"😷",pt:"Ele está gripado",en:"He has a cold"},{emoji:"💡",pt:"Ela tem uma ideia",en:"She has an idea"},{emoji:"📱",pt:"Tem bateria?",en:"Does it have battery?"}]},{id:"like",title:"LIKE",emoji:"❤️👍",description:"Gostar",module:2,order:23,slides:[{type:"title",emoji:"❤️👍",title:"LIKE",subtitle:"Gostar (de algo/alguém)"},{type:"situation",emoji:"🍔",cardClass:"cyan",text:`Almoço de equipe. Colegas americanos pedem mac and cheese. "Do you LIKE it?" Você experimenta e gosta: "I LIKE it!" Mas a maionese? "I don't LIKE mayo."<br><br>LIKE é como a gente faz amizade em inglês. Gostos, preferências, hobbies — tudo passa por LIKE. "Do you like soccer? I like cooking. She likes açaí." Sem LIKE, você não consegue conectar com as pessoas.`},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🧀",english:"Try the mac and cheese! Do you like it?",portuguese:"Experimenta o mac and cheese! Gostou?",breakdown:"<strong>DO YOU LIKE IT</strong> = você gosta? LIKE + coisa. Pergunta básica de preferência."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"🍔",english:"I like it! But I don't like mayo. Do you like Brazilian food?",portuguese:"Gostei! Mas não gosto de maionese. Gosta de comida brasileira?",breakdown:`<strong>I LIKE IT</strong> = gostei/gosto. <strong>I DON'T LIKE</strong> = não gosto. Sem preposição! Não é "like OF".`},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"🍚",english:"I like rice and beans! My wife likes açaí. What do you like to cook?",portuguese:"Gosto de arroz e feijão! Minha esposa gosta de açaí. O que gosta de cozinhar?",breakdown:"<strong>LIKES</strong> = gosta (HE/SHE com -S). <strong>LIKE TO COOK</strong> = gostar de cozinhar. LIKE TO + verbo."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"🔥",english:"I like grilling. I'll make picanha for you guys!",portuguese:"Gosto de grelhar. Vou fazer picanha pra vocês!",breakdown:"<strong>LIKE GRILLING</strong> = gostar de grelhar. LIKE + -ING também funciona. I'LL MAKE = vou fazer."},{type:"rule",cardClass:"cyan",text:"<strong>LIKE</strong> = GOSTAR (de algo):",keyword:"LIKE",keywordAfter:"Gostar de / Curtir"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>LIKE</strong> soa como "LÁIK"<br><strong>LIKES</strong> (he/she) soa como "LÁIKS"'},{type:"example",cardClass:"cyan",emoji:"☕",question:'I <span class="hl-cyan">like</span> coffee.',questionTr:"Eu gosto de café.",answer:"(preferência)",answerTr:"LIKE + coisa"},{type:"example",cardClass:"cyan",emoji:"🎵",question:'I <span class="hl-cyan">like</span> listening to music.',questionTr:"Eu gosto de ouvir música.",answer:"(atividade)",answerTr:"LIKE + -ING"},{type:"example",cardClass:"cyan",emoji:"📚",question:'She <span class="hl-cyan">likes</span> to read.',questionTr:"Ela gosta de ler.",answer:"(atividade)",answerTr:"LIKE + TO + verbo"},{type:"tip",cardClass:"green",icon:"💡",title:"LIKE + VERBO",text:"Duas formas corretas:<br><br><strong>I like swimming.</strong> (LIKE + -ING)<br><strong>I like to swim.</strong> (LIKE TO + verbo)<br><br>Ambas estão corretas!"},{type:"examples",cardClass:"cyan",title:"❤️ LIKE - COISAS",items:[{emoji:"🍕",en:'I <span class="hl-cyan">like</span> pizza.',pt:"Eu gosto de pizza."},{emoji:"🏖️",en:'I <span class="hl-cyan">like</span> the beach.',pt:"Eu gosto da praia."},{emoji:"🐕",en:'I <span class="hl-cyan">like</span> dogs.',pt:"Eu gosto de cachorros."},{emoji:"🎬",en:'I <span class="hl-cyan">like</span> movies.',pt:"Eu gosto de filmes."}]},{type:"examples",cardClass:"purple",title:"❤️ LIKE - ATIVIDADES",items:[{emoji:"💃",en:'I <span class="hl-cyan">like</span> dancing.',pt:"Eu gosto de dançar."},{emoji:"🍳",en:'I <span class="hl-cyan">like</span> cooking.',pt:"Eu gosto de cozinhar."},{emoji:"📚",en:'She <span class="hl-cyan">likes</span> reading.',pt:"Ela gosta de ler."},{emoji:"🎮",en:'He <span class="hl-cyan">likes</span> playing games.',pt:"Ele gosta de jogar."}]},{type:"comparison",cardClass:"red",title:"⚠️ SEM PREPOSIÇÃO!",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"I like of pizza.",leftNote:"Tradução literal do PT",right:"I like pizza.",rightNote:"Sem OF em inglês",explanation:'Em inglês: LIKE + coisa (sem "of")'},{type:"examples",cardClass:"red",title:"❌ NEGATIVO: DON'T LIKE",items:[{emoji:"☕",en:"I <span class='hl-red'>don't like</span> coffee.",pt:"Eu não gosto de café."},{emoji:"🥦",en:"She <span class='hl-red'>doesn't like</span> vegetables.",pt:"Ela não gosta de verduras."}]},{type:"quiz",cardClass:"cyan",question:'🎯 "Eu gosto de pizza" em inglês:',options:["I like of pizza","I like pizza","I like to pizza"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Ela gosta de ler":',options:["She like read","She likes reading","She like to reading"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"Do you _____ music?",correctWord:"like"},{type:"list",cardClass:"gold",title:"📝 RESUMO - LIKE",items:[{emoji:"❤️",text:"<strong>LIKE</strong> = gostar de"},{emoji:"⚠️",text:'Sem OF: I like pizza (não "of pizza")'},{emoji:"🎯",text:"LIKE + -ING ou LIKE TO + verbo"},{emoji:"👤",text:"He/she LIKES (com S)"}]},{type:"end"}],vocabulary:[{emoji:"☕",pt:"Eu gosto de café",en:"I like coffee"},{emoji:"🎵",pt:"Eu gosto de música",en:"I like music"},{emoji:"🍕",pt:"Você gosta de pizza?",en:"Do you like pizza?"},{emoji:"🏖️",pt:"Eu gosto de praia",en:"I like the beach"},{emoji:"📚",pt:"Ela gosta de ler",en:"She likes to read"},{emoji:"🎮",pt:"Ele gosta de jogos",en:"He likes games"},{emoji:"🐕",pt:"Eu gosto de cachorros",en:"I like dogs"},{emoji:"🎬",pt:"Você gosta de filmes?",en:"Do you like movies?"},{emoji:"💃",pt:"Eu gosto de dançar",en:"I like dancing"},{emoji:"🍳",pt:"Eu gosto de cozinhar",en:"I like cooking"}]},{id:"love-hate",title:"LOVE / HATE",emoji:"❤️💔",description:"Gostar muito/Odiar",module:2,order:24,slides:[{type:"title",emoji:"❤️💔",title:"LOVE / HATE",subtitle:"Extremos de preferência"},{type:"situation",emoji:"🚗",cardClass:"cyan",text:'Sexta-feira, 5 da tarde. Você dá carona pro colega e o trânsito tá horrível. "I HATE this traffic!" Mas o fim de semana tá chegando: "I LOVE Fridays!"<br><br>LIKE é gostar. Mas às vezes não é forte o suficiente. Você AMA churrasco? LOVE. Odeia trânsito? HATE. Americanos usam LOVE e HATE o tempo todo — até pra coisas pequenas: "I love this song!" "I hate Mondays."'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🚗",english:"I hate this traffic! Friday afternoon is the worst.",portuguese:"Odeio esse trânsito! Sexta à tarde é o pior.",breakdown:"<strong>I HATE</strong> = eu odeio. THE WORST = o pior. Americanos falam HATE pra coisas do dia a dia."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"🎉",english:"Same. But I love Fridays! My wife loves going out for dinner.",portuguese:"Também. Mas adoro sexta! Minha esposa adora sair pra jantar.",breakdown:"<strong>I LOVE</strong> = eu amo/adoro. <strong>LOVES GOING OUT</strong> = adora sair. LOVE + -ING."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"🎣",english:"I love fishing. Want to come Sunday? I'd love to!",portuguese:"Adoro pescar. Quer ir domingo? Adoraria!",breakdown:"<strong>I'D LOVE TO</strong> = adoraria! Forma educada de aceitar convite. Muito usada."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"😴",english:"Great! I hate waking up early though. Haha, me too!",portuguese:"Ótimo! Mas odeio acordar cedo. Haha, eu também!",breakdown:"<strong>HATE WAKING UP</strong> = odiar acordar. THOUGH = mas/porém. ME TOO = eu também!"},{type:"rule",cardClass:"green",text:"<strong>LOVE</strong> = AMAR / ADORAR (muito positivo):",keyword:"LOVE",keywordAfter:"Eu amo / Eu adoro"},{type:"rule",cardClass:"red",text:"<strong>HATE</strong> = ODIAR / DETESTAR (muito negativo):",keyword:"HATE",keywordAfter:"Eu odeio / Eu detesto"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>LOVE</strong> soa como "LÂV"<br><strong>HATE</strong> soa como "RÊIT"'},{type:"example",cardClass:"green",emoji:"🍫",question:'I <span class="hl-green">love</span> chocolate.',questionTr:"Eu amo chocolate.",answer:"(amar)",answerTr:"Muito positivo"},{type:"example",cardClass:"red",emoji:"🚗",question:'I <span class="hl-red">hate</span> traffic.',questionTr:"Eu odeio trânsito.",answer:"(odiar)",answerTr:"Muito negativo"},{type:"example",cardClass:"green",emoji:"❤️",question:'I <span class="hl-green">love</span> you.',questionTr:"Eu te amo.",answer:"(amor)",answerTr:"A frase mais importante!"},{type:"examples",cardClass:"green",title:"❤️ LOVE - COISAS QUE AMAMOS",items:[{emoji:"🍕",en:'I <span class="hl-green">love</span> pizza.',pt:"Eu adoro pizza."},{emoji:"🎵",en:'I <span class="hl-green">love</span> this song.',pt:"Eu adoro essa música."},{emoji:"🏖️",en:'I <span class="hl-green">love</span> the beach.',pt:"Eu amo a praia."},{emoji:"🎉",en:'I <span class="hl-green">love</span> parties.',pt:"Eu adoro festas."}]},{type:"examples",cardClass:"red",title:"💔 HATE - COISAS QUE ODIAMOS",items:[{emoji:"☔",en:'I <span class="hl-red">hate</span> rain.',pt:"Eu odeio chuva."},{emoji:"⏰",en:'I <span class="hl-red">hate</span> waking up early.',pt:"Eu odeio acordar cedo."},{emoji:"🥶",en:'I <span class="hl-red">hate</span> cold weather.',pt:"Eu odeio frio."},{emoji:"⏳",en:'I <span class="hl-red">hate</span> waiting.',pt:"Eu odeio esperar."}]},{type:"list",cardClass:"gold",title:"📊 ESCALA DE PREFERÊNCIA",items:[{emoji:"❤️",text:"<strong>LOVE</strong> = amar / adorar (+++)"},{emoji:"👍",text:"<strong>LIKE</strong> = gostar (+)"},{emoji:"👎",text:"<strong>DON'T LIKE</strong> = não gostar (-)"},{emoji:"💔",text:"<strong>HATE</strong> = odiar (---)"}]},{type:"tip",cardClass:"green",icon:"💡",title:"LOVE/HATE + VERBO",text:"Igual ao LIKE:<br><br><strong>I love swimming.</strong> (LOVE + -ING)<br><strong>I hate waking up early.</strong> (HATE + -ING)"},{type:"comparison",cardClass:"cyan",title:"👍 LIKE vs LOVE ❤️",leftClass:"left-side",rightClass:"right-side",leftIcon:"👍",rightIcon:"❤️",leftLabel:"LIKE (gostar)",rightLabel:"LOVE (amar)",left:'I <span class="hl-cyan">like</span> coffee.',leftNote:"Gosto normal",right:'I <span class="hl-green">love</span> coffee!',rightNote:"Adoro!",explanation:"LIKE = gostar | LOVE = amar/adorar"},{type:"quiz",cardClass:"cyan",question:'🎯 "Eu adoro pizza" em inglês:',options:["I hate pizza","I like pizza","I love pizza"],correct:2},{type:"quiz",cardClass:"cyan",question:'🎯 "Eu odeio acordar cedo":',options:["I hate waking up early","I hate wake up early","I hate to waking up early"],correct:0},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"I _____ you! (amar)",correctWord:"love"},{type:"list",cardClass:"gold",title:"📝 RESUMO - LOVE / HATE",items:[{emoji:"❤️",text:"<strong>LOVE</strong> = amar / adorar"},{emoji:"💔",text:"<strong>HATE</strong> = odiar / detestar"},{emoji:"🎯",text:"LOVE/HATE + -ING: I love swimming"},{emoji:"⭐",text:"I love you = Eu te amo"}]},{type:"end"}],vocabulary:[{emoji:"🍫",pt:"Eu amo chocolate",en:"I love chocolate"},{emoji:"🚗",pt:"Eu odeio trânsito",en:"I hate traffic"},{emoji:"❤️",pt:"Eu te amo",en:"I love you"},{emoji:"🎵",pt:"Eu adoro essa música",en:"I love this song"},{emoji:"☔",pt:"Eu odeio chuva",en:"I hate rain"},{emoji:"🍕",pt:"Eu adoro pizza",en:"I love pizza"},{emoji:"⏰",pt:"Eu odeio acordar cedo",en:"I hate waking up early"},{emoji:"🏖️",pt:"Eu adoro praia",en:"I love the beach"},{emoji:"🥶",pt:"Eu odeio frio",en:"I hate cold weather"},{emoji:"🎉",pt:"Eu adoro festas",en:"I love parties"}]},{id:"can-permission",title:"CAN (Permission)",emoji:"🙋✅",description:"Posso? (permissão)",module:2,order:25,slides:[{type:"title",emoji:"🙋✅",title:"CAN (Permission)",subtitle:"Pedir e dar permissão"},{type:"situation",emoji:"🏫",cardClass:"cyan",text:'Seu filho tem consulta médica e você precisa buscá-lo mais cedo. Vai na secretaria da escola: "CAN I pick up my son early?" A secretária: "CAN you sign here?"<br><br>No Módulo 1 você aprendeu CAN = habilidade (I CAN drive). Agora é CAN = PERMISSÃO. "CAN I...?" = "Posso...?" É a forma mais natural de pedir permissão nos EUA. Você vai usar CAN I o dia todo.'},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🏫",english:"Hi, can I pick up my son early? He has a doctor's appointment.",portuguese:"Oi, posso buscar meu filho mais cedo? Ele tem consulta.",breakdown:"<strong>CAN I</strong> = posso? Forma mais natural de pedir permissão nos EUA."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"✍️",english:"Sure. Can you sign here, please? Of course.",portuguese:"Claro. Pode assinar aqui? Claro.",breakdown:"<strong>CAN YOU</strong> = você pode? Pedido educado. OF COURSE = claro."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"📋",english:"Can I also get his report card? And can I talk to his teacher?",portuguese:"Posso pegar o boletim também? E posso falar com a professora?",breakdown:"<strong>CAN I ALSO</strong> = posso também? REPORT CARD = boletim escolar. Empilhando pedidos!"},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"🕐",english:"She's in a meeting. Can you come back at 3? No problem!",portuguese:"Ela tá em reunião. Pode voltar às 3? Sem problema!",breakdown:"<strong>CAN YOU COME BACK</strong> = pode voltar? IN A MEETING = em reunião. NO PROBLEM = sem problema."},{type:"rule",cardClass:"cyan",text:"CAN também serve para pedir <strong>PERMISSÃO</strong>:",keyword:"CAN I...?",keywordAfter:"Posso...? (pedindo licença)"},{type:"example",cardClass:"cyan",emoji:"🚻",question:'<span class="hl-cyan">Can I</span> use the bathroom?',questionTr:"Posso usar o banheiro?",answer:"(permissão)",answerTr:"Pedindo licença"},{type:"example",cardClass:"cyan",emoji:"🪑",question:'<span class="hl-cyan">Can I</span> sit here?',questionTr:"Posso sentar aqui?",answer:"(permissão)",answerTr:"Pedindo licença"},{type:"example",cardClass:"cyan",emoji:"🚪",question:'<span class="hl-cyan">Can I</span> come in?',questionTr:"Posso entrar?",answer:"(permissão)",answerTr:"Pedindo licença"},{type:"examples",cardClass:"cyan",title:"🙋 PEDINDO PERMISSÃO",items:[{emoji:"📞",en:'<span class="hl-cyan">Can I</span> call you later?',pt:"Posso te ligar depois?"},{emoji:"❓",en:'<span class="hl-cyan">Can I</span> ask a question?',pt:"Posso fazer uma pergunta?"},{emoji:"💳",en:'<span class="hl-cyan">Can I</span> pay with card?',pt:"Posso pagar com cartão?"},{emoji:"🍕",en:'<span class="hl-cyan">Can I</span> have some more?',pt:"Posso pegar mais?"}]},{type:"tip",cardClass:"green",icon:"💡",title:"RESPOSTAS COMUNS",text:"<strong>Yes, you can.</strong> = Sim, pode.<br><strong>Sure!</strong> = Claro!<br><strong>Of course!</strong> = Claro que pode!<br><strong>No, you can't.</strong> = Não, não pode."},{type:"examples",cardClass:"green",title:"✅ DANDO PERMISSÃO",items:[{emoji:"✅",en:'You <span class="hl-green">can</span> go now.',pt:"Você pode ir agora."},{emoji:"✅",en:'You <span class="hl-green">can</span> use my phone.',pt:"Você pode usar meu celular."},{emoji:"✅",en:'You <span class="hl-green">can</span> take one.',pt:"Você pode pegar um."}]},{type:"comparison",cardClass:"cyan",title:"💪 CAN (habilidade) vs 🙋 CAN (permissão)",leftClass:"left-side",rightClass:"right-side",leftIcon:"💪",rightIcon:"🙋",leftLabel:"HABILIDADE",rightLabel:"PERMISSÃO",left:'I <span class="hl-green">can</span> swim.',leftNote:"Eu SEI nadar",right:'<span class="hl-cyan">Can I</span> swim here?',rightNote:"POSSO nadar aqui?",explanation:"Mesmo verbo, contextos diferentes!"},{type:"tip",cardClass:"gold",icon:"🤵",title:"MAIS EDUCADO: MAY I...?",text:"Em situações formais:<br><br><strong>May I come in?</strong><br>Posso entrar? (mais formal)<br><br>CAN I é comum no dia a dia."},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"Can I to go?",leftNote:"CAN nunca usa TO",right:"Can I go?",rightNote:"Verbo direto",explanation:"CAN + verbo (sem TO!)"},{type:"quiz",cardClass:"cyan",question:'🎯 "Posso entrar?" em inglês:',options:["I can enter?","Can I come in?","Can I to enter?"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Você pode ir" (dando permissão):',options:["You can go","Can you go","You can to go"],correct:0},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete (pedindo permissão):",sentence:"_____ I use your phone?",correctWord:"Can"},{type:"list",cardClass:"gold",title:"📝 RESUMO - CAN (Permissão)",items:[{emoji:"🙋",text:"<strong>CAN I...?</strong> = Posso...?"},{emoji:"✅",text:"<strong>You can...</strong> = Você pode..."},{emoji:"🤵",text:"Formal: MAY I...?"},{emoji:"⚠️",text:'Sem TO: Can I go (não "Can I to go")'}]},{type:"end"}],vocabulary:[{emoji:"🚻",pt:"Posso usar o banheiro?",en:"Can I use the bathroom?"},{emoji:"🪑",pt:"Posso sentar aqui?",en:"Can I sit here?"},{emoji:"🚪",pt:"Posso entrar?",en:"Can I come in?"},{emoji:"📞",pt:"Posso ligar?",en:"Can I call?"},{emoji:"❓",pt:"Posso perguntar?",en:"Can I ask?"},{emoji:"🏠",pt:"Posso ir?",en:"Can I go?"},{emoji:"💬",pt:"Posso falar?",en:"Can I speak?"},{emoji:"👀",pt:"Posso ver?",en:"Can I see?"},{emoji:"💳",pt:"Posso pagar com cartão?",en:"Can I pay with card? / Can I pay by card? / Can I use a card?"},{emoji:"🍕",pt:"Posso pedir mais?",en:"Can I order more?"}]},{id:"go",title:"GO",emoji:"🚶➡️",description:"Ir",module:2,order:26,slides:[{type:"title",emoji:"🚶➡️",title:"GO",subtitle:"Ir (movimento para longe)"},{type:"situation",emoji:"🏠",cardClass:"cyan",text:`Sábado de manhã. Você quer sair com a família: "Let's GO to the park!" Mas antes: "I need to GO to the store." Pro filho: "GO get your shoes!"<br><br>GO é IR — um dos verbos mais usados em qualquer língua. Mas tem uma pegadinha: "Go TO the store" (com TO) mas "Go HOME" (sem TO). E "Let's go!" é a frase que todo americano fala 10 vezes por dia.`},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🌳",english:"Let's go to the park! The weather is nice. Let's go!",portuguese:"Vamos pro parque! O tempo tá bom. Vamos!",breakdown:"<strong>LET'S GO</strong> = vamos! <strong>GO TO</strong> the park = ir AO parque. Precisa de TO antes do lugar."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"🛒",english:"Wait, I need to go to the store first. We need milk.",portuguese:"Espera, preciso ir no mercado antes. Precisa de leite.",breakdown:"<strong>GO TO THE STORE</strong> = ir na loja/mercado. FIRST = primeiro/antes."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"👟",english:"Lucas, go get your shoes! And go brush your teeth!",portuguese:"Lucas, vai pegar seus sapatos! E vai escovar os dentes!",breakdown:"<strong>GO GET</strong> = vai pegar. <strong>GO BRUSH</strong> = vai escovar. GO + verbo = vai fazer (comando)."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"🏠",english:"OK, we're ready. Let's go! We go home at 5, OK?",portuguese:"Pronto. Vamos! A gente volta pra casa às 5, tá?",breakdown:"<strong>GO HOME</strong> = ir pra casa (SEM TO!). Exceção importante: go home, go downtown, go outside."},{type:"rule",cardClass:"cyan",text:"<strong>GO</strong> = IR (movimento para longe de quem fala):",keyword:"GO",keywordAfter:"Ir / Partir / Sair"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>GO</strong> soa como "GÔU"<br><strong>GOES</strong> (he/she) soa como "GÔUZ"<br><strong>WENT</strong> (passado) soa como "UÊNT"'},{type:"example",cardClass:"cyan",emoji:"🏠",question:"I'm <span class='hl-cyan'>going</span> home.",questionTr:"Estou indo pra casa.",answer:"(presente contínuo)",answerTr:"Ação agora"},{type:"example",cardClass:"cyan",emoji:"💼",question:"Let's <span class='hl-cyan'>go</span> to work.",questionTr:"Vamos pro trabalho.",answer:"(ir para)",answerTr:"GO TO + lugar"},{type:"example",cardClass:"cyan",emoji:"🚶",question:"Let's <span class='hl-cyan'>go</span>!",questionTr:"Vamos!",answer:"(partida)",answerTr:"Muito comum!"},{type:"tip",cardClass:"gold",icon:"⚠️",title:"GO HOME (sem TO!)",text:'Alguns lugares NÃO usam TO:<br><br><strong>Go home</strong> (não "go to home")<br><strong>Go there</strong> (não "go to there")<br><strong>Go here</strong> (não "go to here")'},{type:"examples",cardClass:"cyan",title:"🚶 GO + TO + LUGAR",items:[{emoji:"🏪",en:'<span class="hl-cyan">Go to</span> the store.',pt:"Ir à loja."},{emoji:"🛌",en:'<span class="hl-cyan">Go to</span> bed.',pt:"Ir dormir."},{emoji:"🏫",en:'<span class="hl-cyan">Go to</span> school.',pt:"Ir à escola."},{emoji:"🏥",en:'<span class="hl-cyan">Go to</span> the doctor.',pt:"Ir ao médico."}]},{type:"examples",cardClass:"purple",title:"🚶 GO + DIREÇÃO",items:[{emoji:"🔙",en:'<span class="hl-cyan">Go</span> back.',pt:"Voltar."},{emoji:"⬇️",en:'<span class="hl-cyan">Go</span> down.',pt:"Descer."},{emoji:"⬆️",en:'<span class="hl-cyan">Go</span> up.',pt:"Subir."},{emoji:"🏃",en:'<span class="hl-cyan">Go</span> away!',pt:"Vai embora!"}]},{type:"comparison",cardClass:"cyan",title:"🚶 GO vs COME ⬅️",leftClass:"left-side",rightClass:"right-side",leftIcon:"➡️",rightIcon:"⬅️",leftLabel:"GO (para longe)",rightLabel:"COME (para perto)",left:'<span class="hl-cyan">Go</span> there.',leftNote:"Vai LÁ (longe de mim)",right:'<span class="hl-purple">Come</span> here.',rightNote:"Vem AQUI (perto de mim)",explanation:"GO = afasta | COME = aproxima"},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"Let's going!",leftNote:"LET'S + forma base",right:"Let's go!",rightNote:"Forma correta",explanation:"LET'S + verbo na forma base (sem -ING)"},{type:"quiz",cardClass:"cyan",question:'🎯 "Vamos!" em inglês:',options:["Let's going!","Let's go!","Let's to go!"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Ir pra casa":',options:["Go to home","Go home","Go at home"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"Let's _____ to the store.",correctWord:"go"},{type:"list",cardClass:"gold",title:"📝 RESUMO - GO",items:[{emoji:"➡️",text:"<strong>GO</strong> = ir (para longe)"},{emoji:"🏠",text:"GO HOME (sem TO!)"},{emoji:"🏪",text:"GO TO the store/school/work"},{emoji:"🚶",text:"Let's GO! = Vamos!"}]},{type:"end"}],vocabulary:[{emoji:"🏠",pt:"Ir pra casa",en:"Go home"},{emoji:"💼",pt:"Ir pro trabalho",en:"Go to work"},{emoji:"🏪",pt:"Ir à loja",en:"Go to the store"},{emoji:"🛌",pt:"Ir dormir",en:"Go to bed"},{emoji:"🏫",pt:"Ir pra escola",en:"Go to school"},{emoji:"🚶",pt:"Vamos!",en:"Let's go!"},{emoji:"🔙",pt:"Voltar",en:"Go back"},{emoji:"⬇️",pt:"Descer",en:"Go down"},{emoji:"⬆️",pt:"Subir",en:"Go up"},{emoji:"🏃",pt:"Vai embora",en:"Go away"}]},{id:"come",title:"COME",emoji:"🚶⬅️",description:"Vir",module:2,order:27,slides:[{type:"title",emoji:"🚶⬅️",title:"COME",subtitle:"Vir (movimento para perto)"},{type:"situation",emoji:"📱",cardClass:"cyan",text:`Aniversário do seu filho sábado. Você manda áudio pro amigo brasileiro: "COME to Lucas's party! Can your wife COME? Everyone is COMING!"<br><br>COME é VIR — direção de quem fala. "Come here" = vem PRA CÁ (onde eu estou). "Go there" = vai PRA LÁ (longe de mim). COME é convite. GO é saída. "COME to my house" (vem pra cá) vs "GO to the store" (vai pra lá).`},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"🎂",english:"Hey! Come to Lucas's birthday party on Saturday!",portuguese:"Ei! Vem pra festa do Lucas no sábado!",breakdown:"<strong>COME TO</strong> = vem pra. COME = direção de quem FALA (vem pra ONDE EU ESTOU)."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"👨‍👩‍👧",english:"Can your wife come? Bring the kids! Everyone is coming.",portuguese:"Sua esposa pode vir? Traz as crianças! Todo mundo vai.",breakdown:"<strong>CAN SHE COME</strong> = ela pode vir? <strong>EVERYONE IS COMING</strong> = todo mundo vai vir. COME + -ING."},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"🕐",english:"Come around 2 PM. Don't come late! Haha.",portuguese:"Chega por volta das 2. Não chega atrasado! Haha.",breakdown:"<strong>COME AROUND</strong> = chega por volta de. <strong>DON'T COME LATE</strong> = não chega atrasado."},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"🎉",english:"OK, we're coming! Can we bring something? Come as you are!",portuguese:"Vamos sim! Podemos levar algo? Vem como estiver!",breakdown:"<strong>WE'RE COMING</strong> = estamos indo/vamos. <strong>COME AS YOU ARE</strong> = vem como estiver. Expressão acolhedora!"},{type:"rule",cardClass:"cyan",text:"<strong>COME</strong> = VIR (movimento para perto de quem fala):",keyword:"COME",keywordAfter:"Vir / Chegar / Voltar"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>COME</strong> soa como "CÂAM"<br><strong>COMES</strong> (he/she) soa como "CÂAMZ"<br><strong>CAME</strong> (passado) soa como "QUÊIM"'},{type:"example",cardClass:"cyan",emoji:"👋",question:'<span class="hl-cyan">Come</span> here.',questionTr:"Vem aqui.",answer:"(comando)",answerTr:"Aproximação"},{type:"example",cardClass:"cyan",emoji:"🔙",question:"I'll <span class='hl-cyan'>come</span> back.",questionTr:"Eu volto.",answer:"(retorno)",answerTr:"Voltando para você"},{type:"example",cardClass:"cyan",emoji:"🚪",question:'<span class="hl-cyan">Come</span> in!',questionTr:"Entra!",answer:"(convite)",answerTr:"Muito comum!"},{type:"examples",cardClass:"cyan",title:"⬅️ COME - USOS COMUNS",items:[{emoji:"🏠",en:'<span class="hl-cyan">Come</span> to my house.',pt:"Vem pra minha casa."},{emoji:"🎉",en:'<span class="hl-cyan">Come</span> to the party.',pt:"Vem pra festa."},{emoji:"👀",en:'<span class="hl-cyan">Come</span> see this!',pt:"Vem ver isso!"},{emoji:"🤝",en:'<span class="hl-cyan">Come</span> with me.',pt:"Vem comigo."}]},{type:"examples",cardClass:"purple",title:"⬅️ COME + DIREÇÃO",items:[{emoji:"⬇️",en:'<span class="hl-cyan">Come</span> down.',pt:"Desce."},{emoji:"⬆️",en:'<span class="hl-cyan">Come</span> up.',pt:"Sobe."},{emoji:"🔙",en:'<span class="hl-cyan">Come</span> back later.',pt:"Volta depois."},{emoji:"📍",en:'<span class="hl-cyan">Come</span> over.',pt:"Vem aqui (visitar)."}]},{type:"comparison",cardClass:"cyan",title:"➡️ GO vs COME ⬅️",leftClass:"left-side",rightClass:"right-side",leftIcon:"➡️",rightIcon:"⬅️",leftLabel:"GO (eu vou LÁ)",rightLabel:"COME (você vem AQUI)",left:"I'm <span class='hl-cyan'>going</span> to your house.",leftNote:"EU vou PRA LÁ",right:'<span class="hl-purple">Come</span> to my house.',rightNote:"VOCÊ vem PRA CÁ",explanation:"GO = para longe | COME = para perto"},{type:"tip",cardClass:"green",icon:"💡",title:"COME HERE (sem TO!)",text:'Assim como GO:<br><br><strong>Come here</strong> (não "come to here")<br><strong>Come back</strong> (não "come to back")'},{type:"comparison",cardClass:"red",title:"⚠️ ERRO COMUM",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"Come to here.",leftNote:"HERE não precisa de TO",right:"Come here.",rightNote:"Forma correta",explanation:"<strong>HERE</strong> não usa preposição!"},{type:"quiz",cardClass:"cyan",question:'🎯 "Vem aqui" em inglês:',options:["Go here","Come here","Arrive here"],correct:1},{type:"quiz",cardClass:"cyan",question:'🎯 "Entra!" (convidando alguém):',options:["Go in!","Come in!","Enter in!"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"_____ to the party tomorrow!",correctWord:"Come"},{type:"list",cardClass:"gold",title:"📝 RESUMO - COME",items:[{emoji:"⬅️",text:"<strong>COME</strong> = vir (para perto)"},{emoji:"👋",text:"COME HERE = Vem aqui"},{emoji:"🚪",text:"COME IN = Entra"},{emoji:"🔙",text:"COME BACK = Volta"}]},{type:"end"}],vocabulary:[{emoji:"👋",pt:"Vem aqui",en:"Come here"},{emoji:"🔙",pt:"Eu volto",en:"I'll come back"},{emoji:"🚪",pt:"Entra",en:"Come in"},{emoji:"🏠",pt:"Vem pra minha casa",en:"Come to my house"},{emoji:"🎉",pt:"Vem pra festa",en:"Come to the party"},{emoji:"👀",pt:"Vem ver isso",en:"Come see this"},{emoji:"🤝",pt:"Vem comigo",en:"Come with me"},{emoji:"⬇️",pt:"Desce",en:"Come down"},{emoji:"⬆️",pt:"Sobe",en:"Come up"},{emoji:"📅",pt:"Quando você vem?",en:"When are you coming?"}]},{id:"get",title:"GET",emoji:"🎯📦",description:"Pegar/Obter/Ficar",module:2,order:28,slides:[{type:"title",emoji:"🎯📦",title:"GET",subtitle:"O verbo mais versátil!"},{type:"situation",emoji:"🏠",cardClass:"cyan",text:`Você acordou atrasado. Corre pra preparar tudo: "GET up! GET your backpack! It's GETTING cold — GET your jacket!"<br><br>GET é o canivete suíço do inglês — tem uns 6 significados: PEGAR (get the phone), CHEGAR (get home), FICAR (get tired), CONSEGUIR (get a job), RECEBER (get paid), ENTENDER (I get it). Parece muito, mas no dia a dia você vai pegando pelo contexto.`},{type:"sequence-step",stepNumber:1,totalSteps:4,emoji:"⏰",english:"Lucas, get up! We're late! Get your backpack!",portuguese:"Lucas, levanta! Estamos atrasados! Pega sua mochila!",breakdown:"<strong>GET UP</strong> = levantar. <strong>GET YOUR</strong> = pega seu/sua. GET = pegar."},{type:"sequence-step",stepNumber:2,totalSteps:4,emoji:"🧥",english:"It's getting cold outside. Get your jacket. Let's go!",portuguese:"Tá ficando frio lá fora. Pega seu casaco. Vamos!",breakdown:"<strong>GETTING COLD</strong> = ficando frio. GET + adjetivo = FICAR. Outro significado de GET!"},{type:"sequence-step",stepNumber:3,totalSteps:4,emoji:"⛽",english:"I need to get gas. We'll get there on time, don't worry.",portuguese:"Preciso abastecer. A gente chega a tempo, relaxa.",breakdown:"<strong>GET GAS</strong> = abastecer. <strong>GET THERE</strong> = chegar lá. GET = chegar!"},{type:"sequence-step",stepNumber:4,totalSteps:4,emoji:"🏫",english:"We got here just in time! Get out of the car — have a good day!",portuguese:"Chegamos na hora! Sai do carro — tenha um bom dia!",breakdown:"<strong>GOT HERE</strong> = chegamos (passado de GET). <strong>GET OUT</strong> = sai/saia. GET = sair de!"},{type:"rule",cardClass:"cyan",text:"<strong>GET</strong> = verbo coringa com MUITOS significados:",keyword:"GET",keywordAfter:"Pegar / Obter / Ficar / Chegar / Entender"},{type:"tip",cardClass:"orange",icon:"🗣️",title:"PRONÚNCIA",text:'<strong>GET</strong> soa como "GUÉT"<br><strong>GOT</strong> (passado) soa como "GÓT"'},{type:"example",cardClass:"cyan",emoji:"📱",question:'<span class="hl-cyan">Get</span> the phone.',questionTr:"Pega o telefone.",answer:"(pegar)",answerTr:"Obter fisicamente"},{type:"example",cardClass:"cyan",emoji:"😴",question:"I'm <span class='hl-cyan'>getting</span> tired.",questionTr:"Estou ficando cansado.",answer:"(ficar)",answerTr:"Mudança de estado"},{type:"example",cardClass:"cyan",emoji:"🏠",question:'I <span class="hl-cyan">got</span> home late.',questionTr:"Cheguei em casa tarde.",answer:"(chegar)",answerTr:"Chegada"},{type:"list",cardClass:"gold",title:"🎯 SIGNIFICADOS DE GET",items:[{emoji:"📦",text:"<strong>Pegar/Obter:</strong> Get the phone"},{emoji:"😴",text:"<strong>Ficar:</strong> Get tired, get sick"},{emoji:"🏠",text:"<strong>Chegar:</strong> Get home, get there"},{emoji:"💡",text:"<strong>Entender:</strong> I get it!"}]},{type:"examples",cardClass:"cyan",title:"📦 GET = PEGAR/OBTER",items:[{emoji:"🚌",en:'<span class="hl-cyan">Get</span> the bus.',pt:"Pegar o ônibus."},{emoji:"💼",en:'<span class="hl-cyan">Get</span> a job.',pt:"Conseguir um emprego."},{emoji:"📧",en:'I <span class="hl-cyan">got</span> your message.',pt:"Recebi sua mensagem."}]},{type:"examples",cardClass:"purple",title:"😴 GET = FICAR (mudança)",items:[{emoji:"😊",en:'<span class="hl-purple">Get</span> happy.',pt:"Ficar feliz."},{emoji:"🤒",en:'<span class="hl-purple">Get</span> sick.',pt:"Ficar doente."},{emoji:"💍",en:'<span class="hl-purple">Get</span> married.',pt:"Casar (ficar casado)."},{emoji:"😠",en:"Don't <span class='hl-purple'>get</span> angry!",pt:"Não fique bravo!"}]},{type:"tip",cardClass:"green",icon:"💡",title:"I GET IT!",text:`<strong>"I get it!"</strong> = Entendi!<br><strong>"I don't get it."</strong> = Não entendo.<br><br>Expressão muito comum!`},{type:"comparison",cardClass:"red",title:"⚠️ GET HOME (sem TO)",leftClass:"wrong",rightClass:"right",leftIcon:"❌",rightIcon:"✅",leftLabel:"ERRADO",rightLabel:"CERTO",left:"Get to home.",leftNote:"HOME não precisa de TO",right:"Get home.",rightNote:"Direto!",explanation:"<strong>HOME</strong> não precisa de preposição!"},{type:"quiz",cardClass:"cyan",question:'🎯 "Chegar em casa":',options:["arrive home","get home","Ambos estão corretos"],correct:2},{type:"quiz",cardClass:"cyan",question:'🎯 "Estou ficando cansado":',options:["I'm become tired","I'm getting tired","I'm being tired"],correct:1},{type:"fill-blank",cardClass:"cyan",prompt:"✍️ Complete:",sentence:"I don't _____ it. (entender)",correctWord:"get"},{type:"list",cardClass:"gold",title:"📝 RESUMO - GET",items:[{emoji:"📦",text:"<strong>GET</strong> = pegar/obter"},{emoji:"😴",text:"<strong>GET</strong> = ficar (get tired/sick)"},{emoji:"🏠",text:"<strong>GET</strong> = chegar (get home)"},{emoji:"💡",text:"<strong>GET IT</strong> = entender"}]},{type:"end"}],vocabulary:[{emoji:"📱",pt:"Pega o telefone",en:"Get the phone"},{emoji:"😴",pt:"Estou ficando cansado",en:"I'm getting tired"},{emoji:"🏠",pt:"Chegar em casa",en:"Get home"},{emoji:"🚌",pt:"Pegar o ônibus",en:"Get the bus"},{emoji:"💼",pt:"Conseguir um emprego",en:"Get a job"},{emoji:"📧",pt:"Receber uma mensagem",en:"Get a message"},{emoji:"😊",pt:"Ficar feliz",en:"Get happy"},{emoji:"🤒",pt:"Ficar doente",en:"Get sick"},{emoji:"💍",pt:"Casar",en:"Get married"},{emoji:"🤔",pt:"Entender",en:"Get it"}]}];export{e as module2Lessons};
